const LOG_FILE: &str = "raft-log.ndjson";
const SNAPSHOT_FILE: &str = "raft-snapshot.json";
const HARD_STATE_FILE: &str = "raft-hard-state.json";
const HARD_STATE_COMMIT_FILE: &str = "raft-hard-state-commit.slots";
const DATA_DIR_LOCK_FILE: &str = "broker-raft.lock";
const HARD_STATE_COMMIT_SLOT_BYTES: usize = 512;
const HARD_STATE_COMMIT_SLOTS: u64 = 2;
const HARD_STATE_COMMIT_FILE_BYTES: usize =
    HARD_STATE_COMMIT_SLOT_BYTES * HARD_STATE_COMMIT_SLOTS as usize;
const LEARNERS_FILE: &str = "raft-learners.json";
const LOCAL_VOTER_STATE_FILE: &str = "raft-local-voter-state.json";
const SNAPSHOT_PART_FILE_PREFIX: &str = "raft-install-snapshot-";
const SNAPSHOT_PART_FILE_SUFFIX: &str = ".json.part";
const DEFAULT_RAFT_RPC_MAX_FRAME_BYTES: usize = 128 * 1024 * 1024;
const DEFAULT_APPEND_ENTRIES_MAX_ENTRIES: usize = 256;
const DEFAULT_APPEND_ENTRIES_MAX_BYTES: usize = 1024 * 1024;
const DEFAULT_APPEND_ENTRIES_MAX_INLINE_BATCHES: usize = 64;
const DEFAULT_INSTALL_SNAPSHOT_CHUNK_BYTES: usize = 1024 * 1024;
const DEFAULT_INSTALL_SNAPSHOT_MAX_STAGED_BYTES: u64 = 128 * 1024 * 1024;
const DEFAULT_INSTALL_SNAPSHOT_MAX_STAGED_TRANSFERS: usize = 4;
const DEFAULT_INSTALL_SNAPSHOT_STALE_TRANSFER: Duration = Duration::from_secs(30 * 60);
/// Minimum window a follower spends re-discovering the leader and re-forwarding
/// a client request before giving up, when the caller's own `wait` budget is
/// shorter. This lets a request that lands on a follower during a leader
/// election succeed once a new leader settles instead of bouncing back an error.
const DEFAULT_PROXY_RETRY_BUDGET: Duration = Duration::from_secs(2);
/// Delay between follower proxy retry attempts. Re-forwarding is idempotent
/// (keyed by request id), so this only paces leader re-discovery.
const PROXY_RETRY_INTERVAL: Duration = Duration::from_millis(100);
const DEFAULT_CLIENT_BATCH_MAX_ENTRIES: usize = 32;
const DEFAULT_CLIENT_PIPELINE_MAX_BATCHES: usize = 4;
const DEFAULT_CLIENT_BATCH_MAX_PENDING: usize = 8192;
const DEFAULT_CLIENT_BATCH_MAX_DELAY: Duration = Duration::from_millis(1);
const DEFAULT_CLIENT_RESPONSE_CACHE_MAX_ENTRIES: usize = 8192;
const APPEND_ENTRIES_BLOCKING_FRAME_BUILD_BYTES: usize = 256 * 1024;
const APPEND_ENTRIES_BLOCKING_FRAME_BUILD_ENTRIES: usize = 64;
const INSTALL_SNAPSHOT_BLOCKING_FRAME_BUILD_BYTES: usize = 256 * 1024;
const APPLY_COMMITTED_CHUNK_ENTRIES: u64 = 1024;
const RAFT_CONTEXT_VALIDATION_CHUNK_ENTRIES: u64 = 1024;
/// Maximum number of *distinct* keys allowed in a public BrokerRaft composite
/// (multi-key) lock/unlock request. Deliberately capped below the protocol-wide
/// [`MAX_COMPOSITE_KEYS`] so the per-log-index fencing-token reservation in
/// [`deterministic_fencing_seed`] (`index * (MAX_COMPOSITE_KEYS + 1)`) always
/// covers every member key without colliding with the next index's seed. The
/// inner [`Broker`] still permits up to `MAX_COMPOSITE_KEYS`; this bound only
/// governs what the replicated front door admits.
const RAFT_MAX_COMPOSITE_KEYS: usize = 3;
// Compile-time guarantee that the Raft admission cap never exceeds the token
// reservation width the inner broker / fencing seed formula are sized for.
const _: () = assert!(RAFT_MAX_COMPOSITE_KEYS <= MAX_COMPOSITE_KEYS);
const RAFT_FENCING_TOKEN_BASE: u64 = 4_000_000_000_000_000;
const RAFT_CLIENT_ID_PREFIX_SHIFT: u64 = 48;
const RAFT_CLIENT_ID_SEQUENCE_MASK: u64 = (1_u64 << RAFT_CLIENT_ID_PREFIX_SHIFT) - 1;
const RAFT_ROLE_CACHE_FOLLOWER: u8 = 0;
const RAFT_ROLE_CACHE_CANDIDATE: u8 = 1;
const RAFT_ROLE_CACHE_LEADER: u8 = 2;

#[derive(Debug, Clone)]
pub struct BrokerRaftConfig {
    pub broker: BrokerConfig,
    pub enabled: bool,
    pub node_id: String,
    pub bind_addr: Option<SocketAddr>,
    pub advertise_addr: Option<String>,
    pub data_dir: PathBuf,
    /// When true, `BrokerRaft::open` holds an advisory lock in `data_dir` so a
    /// second live BrokerRaft instance cannot append, rewrite, or snapshot the
    /// same files concurrently.
    pub data_dir_lock: bool,
    pub heartbeat_interval: Duration,
    pub election_timeout_min: Duration,
    pub election_timeout_max: Duration,
    /// Target cadence for writing snapshots. Operators can set this to
    /// `30min` to get the "compact about every 30 minutes" behavior, while
    /// compaction itself remains index/snapshot based instead of wall-clock
    /// deletion.
    pub snapshot_interval: Duration,
    pub snapshot_max_log_entries: u64,
    pub snapshot_max_log_bytes: u64,
    /// Keep a small suffix after snapshot compaction for debugging and for
    /// followers that only lag slightly. Entries at or before the installed
    /// snapshot index are still safe to delete.
    pub trailing_log_entries: u64,
    /// Maximum number of log entries sent to one peer in a single
    /// `AppendEntries` RPC. Lagging followers catch up over multiple bounded
    /// batches instead of receiving the entire suffix in one frame.
    pub append_entries_max_entries: usize,
    /// Approximate serialized JSON byte budget for one `AppendEntries` entry
    /// batch. The first entry is still sent even if it exceeds this budget so
    /// progress cannot stall on one large command.
    pub append_entries_max_bytes: usize,
    /// Max bounded `AppendEntries` batches a target-index replication task or
    /// no-target heartbeat/post-commit fanout can send sequentially to one peer
    /// before yielding. This preserves per-peer ordering while avoiding one
    /// fan-out/join round per batch for lagging followers.
    pub append_entries_max_inline_batches: usize,
    /// Serialized snapshot payload bytes per `InstallSnapshot` chunk. Base64
    /// encoding makes the wire frame larger than this raw byte budget.
    pub install_snapshot_chunk_bytes: usize,
    /// Max decoded snapshot payload bytes staged on follower disk for one
    /// `InstallSnapshot` transfer.
    pub install_snapshot_max_staged_bytes: u64,
    /// Max concurrent staged `InstallSnapshot` transfers retained on follower
    /// disk before new transfer starts are rejected.
    pub install_snapshot_max_staged_transfers: usize,
    /// Staged `InstallSnapshot` transfers older than this are discarded.
    /// Cleanup fires proactively in the maintenance loop (at most every
    /// `install_snapshot_stale_transfer_after / 2`) so abandoned part files
    /// are removed even when no new snapshot chunks ever arrive on this node.
    pub install_snapshot_stale_transfer_after: Duration,
    /// Max leader-local client requests to append and replicate in one commit
    /// batch. Membership changes and client-drop cleanup stay serialized.
    pub client_batch_max_entries: usize,
    /// Max configured client batches drained into one append/replicate/commit
    /// cycle when the leader write lane is already under load.
    pub client_pipeline_max_batches: usize,
    /// Max leader-local client requests allowed to wait for the Raft write
    /// lane. This bounds memory during stalled quorum or overloaded leader
    /// periods and rejects before appending to the replicated log.
    pub client_batch_max_pending: usize,
    /// Small coalescing window for leader-local client request batches.
    pub client_batch_max_delay: Duration,
    /// Max recent HTTP/request-id responses retained on a leader for
    /// idempotent retries. This is bounded memory only; the Raft log remains
    /// the source of truth.
    pub client_response_cache_max_entries: usize,
    /// How long a follower keeps re-discovering the leader and re-forwarding a
    /// client request before returning an error, when the caller's own `wait`
    /// budget is shorter. The effective window is `wait.max(proxy_retry_budget)`.
    /// Re-forwarding is idempotent (keyed by request id), so this lets a request
    /// that lands on a follower during a leader election succeed once a new
    /// leader settles instead of bouncing an error back to the load balancer.
    pub proxy_retry_budget: Duration,
    /// When true, every Raft append-log write is flushed to stable storage
    /// before the node acknowledges it. Disabling this is an explicit
    /// performance/benchmark tradeoff and weakens crash durability.
    pub sync_log: bool,
    /// When true, commit-only hard-state slot writes are flushed before the
    /// leader applies committed entries. Disabling this is a separate explicit
    /// benchmark/throughput tradeoff: acknowledged log entries remain written,
    /// but crash recovery may replay only through the last synced commit slot.
    pub sync_commit: bool,
    /// Optional shared secret required on Raft peer RPC frames. When unset,
    /// the peer listener preserves the existing trusted-network behavior.
    pub peer_token: Option<String>,
    pub peers: Vec<RaftPeerConfig>,
}

impl Default for BrokerRaftConfig {
    fn default() -> Self {
        crate::routine_id!("ddl-routine-broker-raft-config-default-1");
        Self {
            broker: BrokerConfig::default(),
            enabled: false,
            node_id: "node-1".into(),
            bind_addr: Some("127.0.0.1:7980".parse().expect("valid default addr")),
            advertise_addr: None,
            data_dir: PathBuf::from("./data/raft/node-1"),
            data_dir_lock: true,
            heartbeat_interval: Duration::from_millis(100),
            election_timeout_min: Duration::from_millis(800),
            election_timeout_max: Duration::from_millis(1_600),
            snapshot_interval: Duration::from_secs(30 * 60),
            snapshot_max_log_entries: 100_000,
            snapshot_max_log_bytes: 64 * 1024 * 1024,
            trailing_log_entries: 10_000,
            append_entries_max_entries: DEFAULT_APPEND_ENTRIES_MAX_ENTRIES,
            append_entries_max_bytes: DEFAULT_APPEND_ENTRIES_MAX_BYTES,
            append_entries_max_inline_batches: DEFAULT_APPEND_ENTRIES_MAX_INLINE_BATCHES,
            install_snapshot_chunk_bytes: DEFAULT_INSTALL_SNAPSHOT_CHUNK_BYTES,
            install_snapshot_max_staged_bytes: DEFAULT_INSTALL_SNAPSHOT_MAX_STAGED_BYTES,
            install_snapshot_max_staged_transfers: DEFAULT_INSTALL_SNAPSHOT_MAX_STAGED_TRANSFERS,
            install_snapshot_stale_transfer_after: DEFAULT_INSTALL_SNAPSHOT_STALE_TRANSFER,
            client_batch_max_entries: DEFAULT_CLIENT_BATCH_MAX_ENTRIES,
            client_pipeline_max_batches: DEFAULT_CLIENT_PIPELINE_MAX_BATCHES,
            client_batch_max_pending: DEFAULT_CLIENT_BATCH_MAX_PENDING,
            client_batch_max_delay: DEFAULT_CLIENT_BATCH_MAX_DELAY,
            client_response_cache_max_entries: DEFAULT_CLIENT_RESPONSE_CACHE_MAX_ENTRIES,
            proxy_retry_budget: DEFAULT_PROXY_RETRY_BUDGET,
            sync_log: true,
            sync_commit: true,
            peer_token: None,
            peers: Vec::new(),
        }
    }
}

impl BrokerRaftConfig {
    pub fn cluster_size(&self) -> usize {
        crate::routine_id!("ddl-routine-broker-raft-cluster-size-1");
        self.peers.len()
    }

    pub fn quorum_size(&self) -> usize {
        crate::routine_id!("ddl-routine-broker-raft-quorum-size-1");
        quorum_for(self.cluster_size())
    }

    pub fn validate(&self) -> Result<(), BrokerRaftError> {
        crate::routine_id!("ddl-routine-broker-raft-validate-1");
        self.validate_for_peer_transport(false)
    }

    fn validate_for_peer_transport(
        &self,
        allow_memory_peer_addrs: bool,
    ) -> Result<(), BrokerRaftError> {
        crate::routine_id!("ddl-routine-broker-raft-validate-transport-1");
        if !self.enabled {
            return Ok(());
        }
        let node_id = self.node_id.trim();
        if node_id.is_empty() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.node_id cannot be empty when Raft is enabled".into(),
            ));
        }
        if let Err(message) = validate_raft_node_id(node_id) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft.node_id `{}` is invalid: {message}",
                self.node_id
            )));
        }
        if self.bind_addr.is_none() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.bind_addr is required when Raft is enabled".into(),
            ));
        }
        if let Some(addr) = self.advertise_addr.as_deref() {
            if addr.trim().is_empty() {
                return Err(BrokerRaftError::InvalidConfig(
                    "raft.advertise_addr must not be empty or whitespace-only when configured"
                        .into(),
                ));
            }
            if let Err(message) =
                validate_raft_peer_addr_for_transport(addr, allow_memory_peer_addrs)
            {
                return Err(BrokerRaftError::InvalidConfig(format!(
                    "raft.advertise_addr has invalid addr `{addr}`: {message}"
                )));
            }
        }
        if self
            .peer_token
            .as_ref()
            .is_some_and(|token| token.trim().is_empty())
        {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.peer_token must not be empty or whitespace-only when configured".into(),
            ));
        }
        let peers =
            validate_membership_peers_for_transport(self.peers.clone(), allow_memory_peer_addrs)?;
        if let Some(local_peer) = peers.iter().find(|p| p.id == node_id) {
            let local_addr = configured_local_raft_advertise_addr(self);
            if local_peer.addr != local_addr {
                return Err(BrokerRaftError::InvalidConfig(format!(
                    "raft local voter `{node_id}` advertises `{local_addr}` but raft.peers lists `{}`; set raft.advertise_addr to the peer address or update raft.peers",
                    local_peer.addr
                )));
            }
        }
        if !peers.iter().any(|p| p.id == node_id) {
            let local_prefix = raft_client_id_prefix(node_id);
            if let Some(peer) = peers
                .iter()
                .find(|peer| raft_client_id_prefix(&peer.id) == local_prefix)
            {
                return Err(BrokerRaftError::InvalidConfig(format!(
                    "raft.node_id `{}` derives the same client-id prefix as raft peer `{}`; rename one node id",
                    node_id, peer.id
                )));
            }
        }
        if peers.len() != self.peers.len() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.peers must not contain duplicate peer IDs".into(),
            ));
        }
        if self.election_timeout_min >= self.election_timeout_max {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.election_timeout_min_ms must be less than raft.election_timeout_max_ms"
                    .into(),
            ));
        }
        if self.heartbeat_interval.is_zero() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.heartbeat_interval_ms must be greater than 0".into(),
            ));
        }
        if self.heartbeat_interval >= self.election_timeout_min {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.heartbeat_interval_ms must be less than raft.election_timeout_min_ms".into(),
            ));
        }
        if self.snapshot_interval.is_zero() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.snapshot_interval_ms must be greater than 0".into(),
            ));
        }
        if self.append_entries_max_entries == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.append_entries_max_entries must be greater than 0".into(),
            ));
        }
        if self.append_entries_max_bytes == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.append_entries_max_bytes must be greater than 0".into(),
            ));
        }
        if self.append_entries_max_inline_batches == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.append_entries_max_inline_batches must be greater than 0".into(),
            ));
        }
        if self.install_snapshot_chunk_bytes == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.install_snapshot_chunk_bytes must be greater than 0".into(),
            ));
        }
        if self.install_snapshot_max_staged_bytes == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.install_snapshot_max_staged_bytes must be greater than 0".into(),
            ));
        }
        if self.install_snapshot_max_staged_transfers == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.install_snapshot_max_staged_transfers must be greater than 0".into(),
            ));
        }
        if self.install_snapshot_stale_transfer_after.is_zero() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.install_snapshot_stale_transfer_ms must be greater than 0".into(),
            ));
        }
        if self.client_batch_max_entries == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.client_batch_max_entries must be greater than 0".into(),
            ));
        }
        if self.client_pipeline_max_batches == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.client_pipeline_max_batches must be greater than 0".into(),
            ));
        }
        if self.client_batch_max_pending == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.client_batch_max_pending must be greater than 0".into(),
            ));
        }
        if self.client_response_cache_max_entries == 0 {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.client_response_cache_max_entries must be greater than 0".into(),
            ));
        }
        if self.proxy_retry_budget.is_zero() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft.proxy_retry_budget_ms must be greater than 0".into(),
            ));
        }
        Ok(())
    }
}

fn configured_local_raft_advertise_addr(config: &BrokerRaftConfig) -> String {
    crate::routine_id!("ddl-routine-broker-raft-configured-local-advertise-addr-1");
    config
        .advertise_addr
        .clone()
        .or_else(|| {
            config
                .bind_addr
                .as_ref()
                .map(std::string::ToString::to_string)
        })
        .unwrap_or_default()
}

