#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(
    tag = "state",
    rename_all = "camelCase",
    rename_all_fields = "camelCase"
)]
pub enum RaftMembership {
    Simple {
        peers: Vec<RaftPeerConfig>,
    },
    Joint {
        old_peers: Vec<RaftPeerConfig>,
        new_peers: Vec<RaftPeerConfig>,
    },
}

impl RaftMembership {
    pub fn from_simple(peers: Vec<RaftPeerConfig>) -> Self {
        crate::routine_id!("ddl-routine-broker-raft-membership-simple-1");
        Self::Simple {
            peers: normalize_peers(peers),
        }
    }

    pub fn active_peers(&self) -> Vec<RaftPeerConfig> {
        crate::routine_id!("ddl-routine-broker-raft-membership-active-1");
        match self {
            Self::Simple { peers } => normalize_peers(peers.clone()),
            Self::Joint {
                old_peers,
                new_peers,
            } => normalize_peers(old_peers.iter().chain(new_peers.iter()).cloned().collect()),
        }
    }

    fn validation_peers(&self) -> Vec<RaftPeerConfig> {
        crate::routine_id!("ddl-routine-broker-raft-membership-validation-peers-1");
        match self {
            Self::Simple { peers } => peers.clone(),
            Self::Joint {
                old_peers,
                new_peers,
            } => old_peers.iter().chain(new_peers.iter()).cloned().collect(),
        }
    }

    pub fn contains_id(&self, node_id: &str) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-membership-contains-1");
        match self {
            Self::Simple { peers } => peers.iter().any(|peer| peer.id == node_id),
            Self::Joint {
                old_peers,
                new_peers,
            } => old_peers
                .iter()
                .chain(new_peers.iter())
                .any(|peer| peer.id == node_id),
        }
    }

    pub fn contains_peer(&self, peer: &RaftPeerConfig) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-membership-contains-peer-1");
        self.active_peers()
            .into_iter()
            .any(|active| active.id == peer.id && active.addr == peer.addr)
    }

    pub fn cluster_size(&self) -> usize {
        crate::routine_id!("ddl-routine-broker-raft-membership-cluster-size-1");
        match self {
            Self::Simple { peers } => peers
                .iter()
                .map(|peer| peer.id.as_str())
                .collect::<BTreeSet<_>>()
                .len(),
            Self::Joint {
                old_peers,
                new_peers,
            } => old_peers
                .iter()
                .chain(new_peers.iter())
                .map(|peer| peer.id.as_str())
                .collect::<BTreeSet<_>>()
                .len(),
        }
    }

    pub fn quorum_size(&self) -> usize {
        crate::routine_id!("ddl-routine-broker-raft-membership-quorum-size-1");
        match self {
            Self::Simple { peers } => quorum_for(peers.len()),
            Self::Joint {
                old_peers,
                new_peers,
            } => joint_quorum_size(old_peers, new_peers),
        }
    }

    pub fn is_joint(&self) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-membership-is-joint-1");
        matches!(self, Self::Joint { .. })
    }

    pub fn quorum_met(&self, ack_ids: &BTreeSet<String>) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-membership-quorum-met-1");
        match self {
            Self::Simple { peers } => {
                !peers.is_empty() && peer_votes(peers, ack_ids) >= quorum_for(peers.len())
            }
            Self::Joint {
                old_peers,
                new_peers,
            } => {
                !old_peers.is_empty()
                    && !new_peers.is_empty()
                    && peer_votes(old_peers, ack_ids) >= quorum_for(old_peers.len())
                    && peer_votes(new_peers, ack_ids) >= quorum_for(new_peers.len())
            }
        }
    }

    fn minimal_quorum_ack_set(&self, local_id: &str) -> Option<BTreeSet<String>> {
        crate::routine_id!("ddl-routine-broker-raft-membership-minimal-quorum-acks-1");
        let mut ack_ids = BTreeSet::new();
        match self {
            Self::Simple { peers } => {
                add_peer_if_present(&mut ack_ids, peers, local_id);
                add_peers_until_quorum(&mut ack_ids, peers, quorum_for(peers.len()));
            }
            Self::Joint {
                old_peers,
                new_peers,
            } => {
                add_peer_if_present(&mut ack_ids, old_peers, local_id);
                add_peer_if_present(&mut ack_ids, new_peers, local_id);
                add_peers_until_quorum(&mut ack_ids, old_peers, quorum_for(old_peers.len()));
                add_peers_until_quorum(&mut ack_ids, new_peers, quorum_for(new_peers.len()));
            }
        }
        self.quorum_met(&ack_ids).then_some(ack_ids)
    }
}

fn quorum_for(cluster_size: usize) -> usize {
    crate::routine_id!("ddl-routine-broker-raft-quorum-for-1");
    if cluster_size == 0 {
        0
    } else {
        (cluster_size / 2) + 1
    }
}

fn joint_quorum_size(old_peers: &[RaftPeerConfig], new_peers: &[RaftPeerConfig]) -> usize {
    crate::routine_id!("ddl-routine-broker-raft-joint-quorum-size-1");
    let old_quorum = quorum_for(old_peers.len());
    let new_quorum = quorum_for(new_peers.len());
    if old_quorum == 0 || new_quorum == 0 {
        return 0;
    }
    let new_ids = new_peers
        .iter()
        .map(|peer| peer.id.as_str())
        .collect::<BTreeSet<_>>();
    let overlap = old_peers
        .iter()
        .filter(|peer| new_ids.contains(peer.id.as_str()))
        .count();
    old_quorum + new_quorum - overlap.min(old_quorum).min(new_quorum)
}

fn normalize_peers(peers: Vec<RaftPeerConfig>) -> Vec<RaftPeerConfig> {
    crate::routine_id!("ddl-routine-broker-raft-normalize-peers-1");
    let mut by_id = BTreeMap::new();
    for peer in peers {
        by_id.insert(peer.id.clone(), peer);
    }
    by_id.into_values().collect()
}

fn peer_votes(peers: &[RaftPeerConfig], ack_ids: &BTreeSet<String>) -> usize {
    crate::routine_id!("ddl-routine-broker-raft-peer-votes-1");
    peers
        .iter()
        .filter(|peer| ack_ids.contains(&peer.id))
        .count()
}

fn select_target_replication_peers(
    membership: &RaftMembership,
    target_index: Option<u64>,
    ack_ids: &BTreeSet<String>,
    mut remote_peers: Vec<(RaftPeerConfig, u64)>,
    fanout_round: u64,
) -> Vec<RaftPeerConfig> {
    crate::routine_id!("ddl-routine-broker-raft-select-target-replication-peers-1");
    let Some(_) = target_index else {
        return remote_peers.into_iter().map(|(peer, _)| peer).collect();
    };
    if membership.quorum_met(ack_ids) {
        return Vec::new();
    }
    if remote_peers.is_empty() {
        return Vec::new();
    }

    let original_remote_peers = remote_peers.clone();
    remote_peers.sort_by(|(left_peer, left_match), (right_peer, right_match)| {
        right_match
            .cmp(left_match)
            .then_with(|| left_peer.id.cmp(&right_peer.id))
    });
    if remote_peers.len() > 1 {
        let offset = fanout_round.saturating_sub(1) as usize % remote_peers.len();
        remote_peers.rotate_left(offset);
    }

    let mut selected = BTreeMap::<String, RaftPeerConfig>::new();
    let mut selected_acks = ack_ids.clone();
    while !membership.quorum_met(&selected_acks) {
        let mut best = None::<(usize, u64, usize)>;
        for (pos, (peer, match_index)) in remote_peers.iter().enumerate() {
            if selected.contains_key(&peer.id) {
                continue;
            }
            let mut candidate_acks = selected_acks.clone();
            candidate_acks.insert(peer.id.clone());
            let gain = quorum_gain(membership, &selected_acks, &candidate_acks);
            if gain == 0 {
                continue;
            }
            let candidate = (gain, *match_index, usize::MAX.saturating_sub(pos));
            if best.is_none_or(|current| candidate > current) {
                best = Some(candidate);
            }
        }
        let Some((_, _, inverted_pos)) = best else {
            return original_remote_peers
                .into_iter()
                .map(|(peer, _)| peer)
                .collect();
        };
        let pos = usize::MAX.saturating_sub(inverted_pos);
        let peer = remote_peers[pos].0.clone();
        selected_acks.insert(peer.id.clone());
        selected.insert(peer.id.clone(), peer);
    }

    if selected.len() >= original_remote_peers.len() {
        return original_remote_peers
            .into_iter()
            .map(|(peer, _)| peer)
            .collect();
    }
    selected.into_values().collect()
}

fn quorum_gain(
    membership: &RaftMembership,
    before: &BTreeSet<String>,
    after: &BTreeSet<String>,
) -> usize {
    crate::routine_id!("ddl-routine-broker-raft-quorum-gain-1");
    match membership {
        RaftMembership::Simple { peers } => peer_votes(peers, after)
            .min(quorum_for(peers.len()))
            .saturating_sub(peer_votes(peers, before).min(quorum_for(peers.len()))),
        RaftMembership::Joint {
            old_peers,
            new_peers,
        } => {
            let old_quorum = quorum_for(old_peers.len());
            let new_quorum = quorum_for(new_peers.len());
            peer_votes(old_peers, after)
                .min(old_quorum)
                .saturating_sub(peer_votes(old_peers, before).min(old_quorum))
                .saturating_add(
                    peer_votes(new_peers, after)
                        .min(new_quorum)
                        .saturating_sub(peer_votes(new_peers, before).min(new_quorum)),
                )
        }
    }
}

fn add_peer_if_present(ack_ids: &mut BTreeSet<String>, peers: &[RaftPeerConfig], peer_id: &str) {
    crate::routine_id!("ddl-routine-broker-raft-add-peer-if-present-1");
    if peers.iter().any(|peer| peer.id == peer_id) {
        ack_ids.insert(peer_id.to_string());
    }
}

fn add_peers_until_quorum(ack_ids: &mut BTreeSet<String>, peers: &[RaftPeerConfig], quorum: usize) {
    crate::routine_id!("ddl-routine-broker-raft-add-peers-until-quorum-1");
    for peer in peers {
        if peer_votes(peers, ack_ids) >= quorum {
            break;
        }
        ack_ids.insert(peer.id.clone());
    }
}

#[cfg(test)]
fn validate_membership_peers(
    peers: Vec<RaftPeerConfig>,
) -> Result<Vec<RaftPeerConfig>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-membership-peers-1");
    validate_membership_peers_for_transport(peers, false)
}

fn validate_membership_peers_for_transport(
    peers: Vec<RaftPeerConfig>,
    allow_memory_peer_addrs: bool,
) -> Result<Vec<RaftPeerConfig>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-membership-peers-1");
    // A cluster needs at least 3 voters for failover. Even sizes (4, 6, ...) are
    // permitted: quorum is always a strict majority (`quorum_for`), so e.g. a
    // 4-node cluster commits with 3 acks and cannot split-brain. Even sizes buy
    // no extra fault tolerance over the next-lower odd size and have marginally
    // higher split-vote odds (mitigated by pre-vote + randomized timeouts), so
    // odd sizes remain the recommended steady state — but even sizes are valid
    // both as a stable config and as the transient step of a membership change
    // such as 5 -> 4 -> 3.
    if peers.len() < 3 {
        return Err(BrokerRaftError::InvalidConfig(
            "raft membership requires at least 3 peers for failover".into(),
        ));
    }

    let mut ids = BTreeSet::new();
    let mut addrs = BTreeSet::new();
    let mut normalized = Vec::with_capacity(peers.len());
    for mut peer in peers {
        peer.id = peer.id.trim().to_string();
        peer.addr = peer.addr.trim().to_string();
        if peer.id.is_empty() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft peer id cannot be empty".into(),
            ));
        }
        if let Err(message) = validate_raft_node_id(&peer.id) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer id `{}` is invalid: {message}",
                peer.id
            )));
        }
        if peer.addr.is_empty() {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer `{}` has an empty addr",
                peer.id
            )));
        }
        if let Err(message) =
            validate_raft_peer_addr_for_transport(&peer.addr, allow_memory_peer_addrs)
        {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer `{}` has invalid addr `{}`: {message}",
                peer.id, peer.addr
            )));
        }
        if !ids.insert(peer.id.clone()) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer id `{}` appears more than once",
                peer.id
            )));
        }
        if !addrs.insert(peer.addr.clone()) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer addr `{}` appears more than once",
                peer.addr
            )));
        }
        normalized.push(peer);
    }
    let normalized = normalize_peers(normalized);
    validate_raft_client_id_prefixes(&normalized)?;
    Ok(normalized)
}

fn validate_raft_node_id(id: &str) -> Result<(), String> {
    crate::routine_id!("ddl-routine-broker-raft-validate-node-id-1");
    if id.is_empty() {
        return Err("cannot be empty".into());
    }
    if id.chars().any(char::is_whitespace) {
        return Err("must not contain whitespace".into());
    }
    if id.chars().any(char::is_control) {
        return Err("must not contain control characters".into());
    }
    if id.contains('/') || id.contains('\\') {
        return Err("must not contain path separators".into());
    }
    Ok(())
}

fn validate_raft_node_id_set(
    ids: Vec<String>,
    subject: &str,
) -> Result<BTreeSet<String>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-node-id-set-1");
    if ids.is_empty() {
        return Err(BrokerRaftError::InvalidConfig(format!(
            "{subject} requires at least one id"
        )));
    }
    let mut normalized = BTreeSet::new();
    for id in ids {
        let id = id.trim().to_string();
        if let Err(message) = validate_raft_node_id(&id) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "{subject} id `{id}` is invalid: {message}"
            )));
        }
        normalized.insert(id);
    }
    Ok(normalized)
}

fn validate_raft_peer_addr_for_transport(
    addr: &str,
    allow_memory_peer_addrs: bool,
) -> Result<(), String> {
    crate::routine_id!("ddl-routine-broker-raft-validate-peer-addr-1");
    if let Some(node_name) = addr.strip_prefix("memory://") {
        if !allow_memory_peer_addrs {
            return Err(
                "memory:// peer addresses are only valid for the in-memory Raft simulator".into(),
            );
        }
        if let Err(message) = validate_raft_node_id(node_name) {
            return Err(format!("memory:// peer address node name {message}"));
        }
        return Ok(());
    }

    if let Some(after_open) = addr.strip_prefix('[') {
        let Some(close) = after_open.find(']') else {
            return Err("bracketed IPv6 peer address must include a closing `]`".into());
        };
        let host = &after_open[..close];
        let suffix = &after_open[close + 1..];
        validate_raft_peer_addr_host(host)?;
        if !suffix.starts_with(':') || suffix.len() == 1 {
            return Err("bracketed IPv6 peer address must be formatted as [addr]:port".into());
        }
        return validate_raft_peer_addr_port(&suffix[1..]);
    }

    let Some((host, port)) = addr.rsplit_once(':') else {
        return Err("peer address must be formatted as host:port".into());
    };
    validate_raft_peer_addr_host(host)?;
    if host.contains(':') {
        return Err("IPv6 peer addresses must be formatted as [addr]:port".into());
    }
    if host.contains('[') || host.contains(']') {
        return Err("peer address host must not contain brackets unless it is [addr]:port".into());
    }
    validate_raft_peer_addr_port(port)
}

fn validate_raft_peer_addr_host(host: &str) -> Result<(), String> {
    crate::routine_id!("ddl-routine-broker-raft-validate-peer-addr-host-1");
    if host.is_empty() {
        return Err("peer address host cannot be empty".into());
    }
    if host.chars().any(char::is_whitespace) {
        return Err("peer address host must not contain whitespace".into());
    }
    if host.chars().any(char::is_control) {
        return Err("peer address host must not contain control characters".into());
    }
    if host.contains('/') || host.contains('\\') {
        return Err("peer address host must not contain URL or path separators".into());
    }
    Ok(())
}

fn validate_raft_peer_addr_port(port: &str) -> Result<(), String> {
    crate::routine_id!("ddl-routine-broker-raft-validate-peer-addr-port-1");
    if port.is_empty() {
        return Err("peer address port cannot be empty".into());
    }
    let port = port
        .parse::<u16>()
        .map_err(|_| "peer address port must be an integer from 1 to 65535".to_string())?;
    if port == 0 {
        return Err("peer address port must be greater than 0".into());
    }
    Ok(())
}

fn validate_raft_client_id_prefixes(peers: &[RaftPeerConfig]) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-client-prefixes-1");
    let mut by_prefix = BTreeMap::<u64, String>::new();
    for peer in peers {
        let prefix = raft_client_id_prefix(&peer.id);
        if let Some(previous) = by_prefix.get(&prefix) {
            if previous == &peer.id {
                continue;
            }
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft peer ids `{previous}` and `{}` derive the same client-id prefix {prefix}; rename one peer id",
                peer.id
            )));
        }
        by_prefix.insert(prefix, peer.id.clone());
    }
    Ok(())
}

fn raft_client_id_for_node(node_id: &str, sequence: u64) -> ClientId {
    crate::routine_id!("ddl-routine-broker-raft-client-id-for-node-1");
    let sequence = (sequence & RAFT_CLIENT_ID_SEQUENCE_MASK).max(1);
    (raft_client_id_prefix(node_id) << RAFT_CLIENT_ID_PREFIX_SHIFT) | sequence
}

fn raft_client_id_prefix(node_id: &str) -> u64 {
    crate::routine_id!("ddl-routine-broker-raft-client-id-prefix-1");
    (stable_node_jitter(node_id, 0) & 0xffff).max(1)
}

#[cfg(test)]
fn validate_staged_learner_peers(
    learners: Vec<RaftPeerConfig>,
    active_peers: &[RaftPeerConfig],
) -> Result<Vec<RaftPeerConfig>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-staged-learners-1");
    validate_staged_learner_peers_for_transport(learners, active_peers, false)
}

fn validate_staged_learner_peers_for_transport(
    learners: Vec<RaftPeerConfig>,
    active_peers: &[RaftPeerConfig],
    allow_memory_peer_addrs: bool,
) -> Result<Vec<RaftPeerConfig>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-staged-learners-1");
    let normalized =
        validate_staged_learner_peer_shapes_for_transport(learners, allow_memory_peer_addrs)?;
    let active_ids = active_peers
        .iter()
        .map(|peer| peer.id.clone())
        .collect::<BTreeSet<_>>();
    let active_addrs = active_peers
        .iter()
        .map(|peer| peer.addr.clone())
        .collect::<BTreeSet<_>>();
    for peer in &normalized {
        if active_ids.contains(&peer.id) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner `{}` is already an active voter",
                peer.id
            )));
        }
        if active_addrs.contains(&peer.addr) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner addr `{}` is already used by an active voter",
                peer.addr
            )));
        }
    }
    let mut combined = active_peers.to_vec();
    combined.extend(normalized.clone());
    validate_raft_client_id_prefixes(&combined)?;
    Ok(normalized)
}

fn validate_staged_learner_peer_shapes_for_transport(
    learners: Vec<RaftPeerConfig>,
    allow_memory_peer_addrs: bool,
) -> Result<Vec<RaftPeerConfig>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-staged-learner-shapes-1");
    let mut ids = BTreeSet::new();
    let mut addrs = BTreeSet::new();
    let mut normalized = Vec::new();
    for mut peer in learners {
        peer.id = peer.id.trim().to_string();
        peer.addr = peer.addr.trim().to_string();
        if peer.id.trim().is_empty() {
            return Err(BrokerRaftError::InvalidConfig(
                "raft learner id cannot be empty".into(),
            ));
        }
        if let Err(message) = validate_raft_node_id(&peer.id) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner id `{}` is invalid: {message}",
                peer.id
            )));
        }
        if peer.addr.trim().is_empty() {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner `{}` addr cannot be empty",
                peer.id
            )));
        }
        if let Err(message) =
            validate_raft_peer_addr_for_transport(&peer.addr, allow_memory_peer_addrs)
        {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner `{}` has invalid addr `{}`: {message}",
                peer.id, peer.addr
            )));
        }
        if !ids.insert(peer.id.clone()) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner id `{}` appears more than once",
                peer.id
            )));
        }
        if !addrs.insert(peer.addr.clone()) {
            return Err(BrokerRaftError::InvalidConfig(format!(
                "raft learner addr `{}` appears more than once",
                peer.addr
            )));
        }
        normalized.push(peer);
    }
    let normalized = normalize_peers(normalized);
    validate_raft_client_id_prefixes(&normalized)?;
    Ok(normalized)
}

#[cfg(test)]
fn validate_raft_membership(membership: RaftMembership) -> Result<RaftMembership, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-membership-1");
    validate_raft_membership_for_transport(membership, false)
}

fn validate_raft_membership_for_transport(
    membership: RaftMembership,
    allow_memory_peer_addrs: bool,
) -> Result<RaftMembership, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-membership-1");
    match membership {
        RaftMembership::Simple { peers } => Ok(RaftMembership::Simple {
            peers: validate_membership_peers_for_transport(peers, allow_memory_peer_addrs)?,
        }),
        RaftMembership::Joint {
            old_peers,
            new_peers,
        } => {
            let old_peers =
                validate_membership_peers_for_transport(old_peers, allow_memory_peer_addrs)?;
            let new_peers =
                validate_membership_peers_for_transport(new_peers, allow_memory_peer_addrs)?;
            validate_joint_membership_cross_addresses(&old_peers, &new_peers)?;
            let mut joint_peers = old_peers.clone();
            joint_peers.extend(new_peers.clone());
            validate_raft_client_id_prefixes(&joint_peers)?;
            Ok(RaftMembership::Joint {
                old_peers,
                new_peers,
            })
        }
    }
}

fn validate_joint_membership_cross_addresses(
    old_peers: &[RaftPeerConfig],
    new_peers: &[RaftPeerConfig],
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-joint-cross-addrs-1");
    let old_by_addr = old_peers
        .iter()
        .map(|peer| (peer.addr.as_str(), peer.id.as_str()))
        .collect::<BTreeMap<_, _>>();
    for peer in new_peers {
        if let Some(old_id) = old_by_addr.get(peer.addr.as_str()) {
            if *old_id != peer.id.as_str() {
                return Err(BrokerRaftError::InvalidConfig(format!(
                    "raft joint membership addr `{}` is shared by peer `{}` in the old config and peer `{}` in the new config",
                    peer.addr, old_id, peer.id
                )));
            }
        }
    }
    Ok(())
}

fn validate_raft_command(command: &RaftCommand) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-command-1");
    match command {
        RaftCommand::SetMembership { membership } => {
            validate_raft_membership_for_transport(membership.clone(), true)?;
        }
        RaftCommand::SetStagedLearners { learners } => {
            validate_staged_learner_peers_for_transport(learners.clone(), &[], true)?;
        }
        RaftCommand::ClientRequestWithIdentity {
            request,
            request_id,
            request_fingerprint: fingerprint,
            ..
        } => {
            validate_replicated_client_request(request)?;
            if request_id.is_empty() {
                return Err(BrokerRaftError::InvalidAppendEntries(
                    "client request identity has empty request id".into(),
                ));
            }
            if fingerprint.is_empty() {
                return Err(BrokerRaftError::InvalidAppendEntries(
                    "client request identity has empty request fingerprint".into(),
                ));
            }
            let expected = request_fingerprint(request).map_err(|err| {
                BrokerRaftError::InvalidAppendEntries(format!(
                    "client request identity fingerprint could not be computed: {err}"
                ))
            })?;
            if fingerprint != &expected {
                return Err(BrokerRaftError::InvalidAppendEntries(
                    "client request identity fingerprint does not match request payload".into(),
                ));
            }
        }
        RaftCommand::ClientRequest { request, .. } => {
            validate_replicated_client_request(request)?;
        }
        RaftCommand::Noop | RaftCommand::DropClient { .. } => {}
    }
    Ok(())
}

fn validate_replicated_client_request(request: &Request) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-replicated-client-request-1");
    ensure_replicable_raft_client_request(request).map_err(|err| {
        BrokerRaftError::InvalidAppendEntries(format!(
            "unsupported replicated client request: {err}"
        ))
    })
}

fn validate_staged_learner_entries_against_membership<'a>(
    mut membership: RaftMembership,
    entries: impl IntoIterator<Item = &'a RaftLogEntry>,
    allow_memory_peer_addrs: bool,
) -> Result<RaftMembership, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-learner-entry-context-1");
    for entry in entries {
        match &entry.command {
            RaftCommand::SetMembership {
                membership: next_membership,
            } => {
                membership = validate_raft_membership_for_transport(
                    next_membership.clone(),
                    allow_memory_peer_addrs,
                )
                .map_err(|err| {
                    BrokerRaftError::InvalidAppendEntries(format!(
                        "entry index {} has invalid membership command: {err}",
                        entry.index
                    ))
                })?;
            }
            RaftCommand::SetStagedLearners { learners } => {
                validate_staged_learner_peers_for_transport(
                    learners.clone(),
                    &membership.validation_peers(),
                    allow_memory_peer_addrs,
                )
                .map_err(|err| {
                    BrokerRaftError::InvalidAppendEntries(format!(
                        "entry index {} has staged learners invalid for active membership: {err}",
                        entry.index
                    ))
                })?;
            }
            RaftCommand::Noop
            | RaftCommand::ClientRequest { .. }
            | RaftCommand::ClientRequestWithIdentity { .. }
            | RaftCommand::DropClient { .. } => {}
        }
    }
    Ok(membership)
}

fn validate_snapshot_client_response_entries(
    entries: &[ClientResponseSnapshotEntry],
) -> Result<BTreeMap<String, String>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-snapshot-client-responses-1");
    let mut fingerprints = BTreeMap::new();
    for entry in entries {
        if entry.request_id.is_empty() || entry.request_fingerprint.is_empty() {
            return Err(BrokerRaftError::InvalidLog(
                "snapshot client response entry has empty request id or fingerprint".into(),
            ));
        }
        if fingerprints
            .insert(entry.request_id.clone(), entry.request_fingerprint.clone())
            .is_some()
        {
            return Err(BrokerRaftError::InvalidLog(format!(
                "snapshot client response entry duplicates request id `{}`",
                entry.request_id
            )));
        }
    }
    Ok(fingerprints)
}

fn validate_client_request_identity_entries(
    mut fingerprints: BTreeMap<String, String>,
    entries: &[RaftLogEntry],
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-request-identity-context-1");
    add_client_request_identity_entries(&mut fingerprints, entries)
}

fn add_client_request_identity_entries(
    fingerprints: &mut BTreeMap<String, String>,
    entries: &[RaftLogEntry],
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-add-request-identity-context-1");
    for entry in entries {
        let RaftCommand::ClientRequestWithIdentity {
            request_id,
            request_fingerprint,
            ..
        } = &entry.command
        else {
            continue;
        };
        if let Some(previous) = fingerprints.get(request_id) {
            if previous != request_fingerprint {
                return Err(BrokerRaftError::InvalidLog(format!(
                    "entry index {} reuses request id `{}` with a different request fingerprint",
                    entry.index, request_id
                )));
            }
        } else {
            fingerprints.insert(request_id.clone(), request_fingerprint.clone());
        }
    }
    Ok(())
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct RetainedRequestIdentityFingerprint {
    request_fingerprint: String,
    first_index: u64,
}

fn retained_request_identity_fingerprints(
    entries: &[RaftLogEntry],
) -> Result<BTreeMap<String, RetainedRequestIdentityFingerprint>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-retained-request-identity-cache-1");
    let mut fingerprints = BTreeMap::new();
    add_retained_request_identity_entries(&mut fingerprints, entries)?;
    Ok(fingerprints)
}

fn add_retained_request_identity_entries(
    fingerprints: &mut BTreeMap<String, RetainedRequestIdentityFingerprint>,
    entries: &[RaftLogEntry],
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-add-retained-request-identity-cache-1");
    for entry in entries {
        let RaftCommand::ClientRequestWithIdentity {
            request_id,
            request_fingerprint,
            ..
        } = &entry.command
        else {
            continue;
        };
        if let Some(previous) = fingerprints.get_mut(request_id) {
            if previous.request_fingerprint != *request_fingerprint {
                return Err(BrokerRaftError::InvalidLog(format!(
                    "entry index {} reuses request id `{}` with a different request fingerprint",
                    entry.index, request_id
                )));
            }
            previous.first_index = previous.first_index.min(entry.index);
        } else {
            fingerprints.insert(
                request_id.clone(),
                RetainedRequestIdentityFingerprint {
                    request_fingerprint: request_fingerprint.clone(),
                    first_index: entry.index,
                },
            );
        }
    }
    Ok(())
}

fn truncate_retained_request_identity_fingerprints(
    fingerprints: &mut BTreeMap<String, RetainedRequestIdentityFingerprint>,
    retained_prefix_last_index: u64,
) {
    crate::routine_id!("ddl-routine-broker-raft-truncate-retained-request-identity-cache-1");
    if retained_prefix_last_index == 0 {
        fingerprints.clear();
    } else {
        fingerprints.retain(|_, fingerprint| fingerprint.first_index <= retained_prefix_last_index);
    }
}

fn entries_have_client_request_identities(entries: &[RaftLogEntry]) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-entries-have-request-identities-1");
    entries
        .iter()
        .any(|entry| matches!(entry.command, RaftCommand::ClientRequestWithIdentity { .. }))
}

fn validate_repaired_request_identity_context(
    snapshot_client_response_fingerprints: &BTreeMap<String, String>,
    retained_request_fingerprints: &BTreeMap<String, RetainedRequestIdentityFingerprint>,
    retained_prefix_last_index: u64,
    suffix: &[RaftLogEntry],
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-repaired-request-identity-context-1");
    if !entries_have_client_request_identities(suffix) {
        return Ok(());
    }
    let mut incoming_fingerprints = BTreeMap::new();
    for entry in suffix {
        let RaftCommand::ClientRequestWithIdentity {
            request_id,
            request_fingerprint,
            ..
        } = &entry.command
        else {
            continue;
        };
        if let Some(snapshot_fingerprint) = snapshot_client_response_fingerprints.get(request_id) {
            if snapshot_fingerprint != request_fingerprint {
                return Err(BrokerRaftError::InvalidAppendEntries(format!(
                    "entry index {} reuses request id `{}` with a different request fingerprint from snapshotted idempotency context",
                    entry.index, request_id
                )));
            }
        }
        if let Some(retained_fingerprint) =
            retained_request_fingerprints
                .get(request_id)
                .filter(|fingerprint| {
                    retained_prefix_last_index > 0
                        && fingerprint.first_index <= retained_prefix_last_index
                })
        {
            if retained_fingerprint.request_fingerprint != *request_fingerprint {
                return Err(BrokerRaftError::InvalidAppendEntries(format!(
                    "entry index {} reuses request id `{}` with a different request fingerprint from retained log context",
                    entry.index, request_id
                )));
            }
        }
        if let Some(previous) =
            incoming_fingerprints.insert(request_id.clone(), request_fingerprint.clone())
        {
            if previous != *request_fingerprint {
                return Err(BrokerRaftError::InvalidAppendEntries(format!(
                    "entry index {} reuses request id `{}` with a different request fingerprint inside append entries",
                    entry.index, request_id
                )));
            }
        }
    }
    Ok(())
}

fn validate_retained_log_context_on_open(
    node_id: &str,
    log: &RaftLogStore,
    recovered_membership: RaftMembership,
    snapshot_client_response_fingerprints: BTreeMap<String, String>,
    snapshot_index: u64,
    allow_memory_peer_addrs: bool,
    telemetry: &BrokerRaftTelemetry,
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-open-log-context-1");
    let last_index = log.last_index();
    let start_index = snapshot_index.saturating_add(1).max(1);
    if start_index > last_index {
        debug!(
            target: "lmx::raft",
            node_id,
            snapshot_index,
            last_log_index = last_index,
            "raft startup retained-log context validation skipped because no retained suffix is present",
        );
        return Ok(());
    }

    telemetry
        .open_log_context_validations_total
        .fetch_add(1, Ordering::Relaxed);
    let started = Instant::now();
    let mut membership = recovered_membership;
    let mut request_fingerprints = snapshot_client_response_fingerprints;
    let mut checked_entries = 0u64;
    let mut chunk_start = start_index;
    while chunk_start <= last_index {
        let chunk_end = last_index.min(
            chunk_start
                .saturating_add(RAFT_CONTEXT_VALIDATION_CHUNK_ENTRIES)
                .saturating_sub(1),
        );
        let entries = match log.entries_range(chunk_start, chunk_end) {
            Ok(entries) => entries,
            Err(err) => {
                let elapsed_us = duration_us_u64(started.elapsed());
                telemetry
                    .open_log_context_validation_errors_total
                    .fetch_add(1, Ordering::Relaxed);
                error!(
                    target: "lmx::raft",
                    node_id,
                    snapshot_index,
                    first_checked_index = start_index,
                    last_checked_index = last_index,
                    chunk_start,
                    chunk_end,
                    checked_entries,
                    elapsed_us,
                    error = %err,
                    "raft startup rejected retained log range gap before committed replay",
                );
                return Err(err);
            }
        };
        if entries.first().map(|entry| entry.index) != Some(chunk_start)
            || entries.last().map(|entry| entry.index) != Some(chunk_end)
        {
            let elapsed_us = duration_us_u64(started.elapsed());
            telemetry
                .open_log_context_validation_errors_total
                .fetch_add(1, Ordering::Relaxed);
            error!(
                target: "lmx::raft",
                node_id,
                snapshot_index,
                first_checked_index = start_index,
                last_checked_index = last_index,
                chunk_start,
                chunk_end,
                first_retained_index = ?entries.first().map(|entry| entry.index),
                last_retained_index = ?entries.last().map(|entry| entry.index),
                checked_entries,
                elapsed_us,
                "raft startup rejected retained log range gap before committed replay",
            );
            return Err(BrokerRaftError::InvalidLog(format!(
                "retained raft log is missing startup validation range {}..={}",
                chunk_start, chunk_end
            )));
        }
        checked_entries = checked_entries.saturating_add(entries.len() as u64);
        match validate_staged_learner_entries_against_membership(
            membership,
            &entries,
            allow_memory_peer_addrs,
        ) {
            Ok(next_membership) => membership = next_membership,
            Err(err) => {
                let elapsed_us = duration_us_u64(started.elapsed());
                telemetry
                    .open_log_context_validation_errors_total
                    .fetch_add(1, Ordering::Relaxed);
                error!(
                    target: "lmx::raft",
                    node_id,
                    snapshot_index,
                    first_checked_index = start_index,
                    last_checked_index = last_index,
                    chunk_start,
                    chunk_end,
                    checked_entries,
                    elapsed_us,
                    error = %err,
                    "raft startup rejected retained log context before committed replay",
                );
                return Err(BrokerRaftError::InvalidLog(format!(
                    "retained raft log has invalid staged learner context: {err}"
                )));
            }
        }
        if let Err(err) = add_client_request_identity_entries(&mut request_fingerprints, &entries) {
            let elapsed_us = duration_us_u64(started.elapsed());
            telemetry
                .open_log_context_validation_errors_total
                .fetch_add(1, Ordering::Relaxed);
            error!(
                target: "lmx::raft",
                node_id,
                snapshot_index,
                first_checked_index = start_index,
                last_checked_index = last_index,
                chunk_start,
                chunk_end,
                checked_entries,
                elapsed_us,
                error = %err,
                "raft startup rejected retained log request identity context before committed replay",
            );
            return Err(BrokerRaftError::InvalidLog(format!(
                "retained raft log has invalid request identity context: {err}"
            )));
        }
        chunk_start = chunk_end.saturating_add(1);
    }
    let elapsed_us = duration_us_u64(started.elapsed());
    telemetry
        .open_log_context_validation_entries_total
        .fetch_add(checked_entries, Ordering::Relaxed);
    telemetry
        .open_log_context_validation_us_total
        .fetch_add(elapsed_us, Ordering::Relaxed);

    debug!(
        target: "lmx::raft",
        node_id,
        snapshot_index,
        first_checked_index = start_index,
        last_checked_index = last_index,
        checked_entries,
        elapsed_us,
        "raft startup validated retained log context before committed replay",
    );
    Ok(())
}

fn raft_command_kind(command: &RaftCommand) -> &'static str {
    crate::routine_id!("ddl-routine-broker-raft-command-kind-1");
    match command {
        RaftCommand::Noop => "noop",
        RaftCommand::ClientRequest { .. } => "client_request",
        RaftCommand::ClientRequestWithIdentity { .. } => "client_request_with_identity",
        RaftCommand::DropClient { .. } => "drop_client",
        RaftCommand::SetMembership { .. } => "set_membership",
        RaftCommand::SetStagedLearners { .. } => "set_staged_learners",
    }
}

#[derive(Debug, thiserror::Error)]
pub enum BrokerRaftError {
    #[error("raft storage I/O error: {0}")]
    Io(#[from] std::io::Error),
    #[error("raft storage JSON error: {0}")]
    Json(#[from] serde_json::Error),
    #[error("invalid raft config: {0}")]
    InvalidConfig(String),
    #[error("unsupported raft client request: {0}")]
    UnsupportedClientRequest(String),
    #[error("cannot compact through index {through_index}; latest snapshot only covers {snapshot_index}")]
    CompactionAheadOfSnapshot {
        through_index: u64,
        snapshot_index: u64,
    },
    #[error("cannot compact raft log before a snapshot has been written")]
    NoSnapshot,
    #[error("raft node is not leader; leader={leader_id:?} addr={leader_addr:?}")]
    NotLeader {
        leader_id: Option<String>,
        leader_addr: Option<String>,
    },
    #[error("raft quorum unavailable for log index {index}; votes={votes} quorum={quorum}")]
    QuorumUnavailable {
        index: u64,
        votes: usize,
        quorum: usize,
    },
    #[error("raft snapshot at index {index} is missing payload checksum")]
    SnapshotChecksumMissing { index: u64 },
    #[error(
        "raft snapshot payload checksum mismatch at index {index}; expected={expected} actual={actual}"
    )]
    SnapshotChecksumMismatch {
        index: u64,
        expected: String,
        actual: String,
    },
    #[error("raft broker snapshot error: {0}")]
    BrokerSnapshot(String),
    #[error("invalid raft append entries: {0}")]
    InvalidAppendEntries(String),
    #[error(
        "single-entry AppendEntries RPC frame has {frame_bytes} bytes, exceeding configured max frame bytes {max_frame_bytes}"
    )]
    AppendEntriesFrameTooLarge {
        frame_bytes: usize,
        max_frame_bytes: usize,
    },
    #[error("invalid persisted raft log: {0}")]
    InvalidLog(String),
    #[error("raft learner `{peer_id}` did not catch up to index {target_index} before promotion")]
    LearnerCatchUpFailed { peer_id: String, target_index: u64 },
    #[error("raft leader client request queue full; pending={pending} limit={limit}")]
    ClientQueueFull { pending: usize, limit: usize },
    #[error("raft request id `{request_id}` was reused with a different request payload")]
    IdempotencyKeyConflict { request_id: String },
    #[error("raft RPC error: {0}")]
    Rpc(String),
}

