    pub fn log(&self) -> &RaftLogStore {
        crate::routine_id!("ddl-routine-broker-raft-log-1");
        &self.log
    }

    fn role_cache_value(role: RaftRole) -> u8 {
        crate::routine_id!("ddl-routine-broker-raft-role-cache-value-1");
        match role {
            RaftRole::Follower => RAFT_ROLE_CACHE_FOLLOWER,
            RaftRole::Candidate => RAFT_ROLE_CACHE_CANDIDATE,
            RaftRole::Leader => RAFT_ROLE_CACHE_LEADER,
        }
    }

    fn publish_role_cache(&self, role: RaftRole, term: u64) {
        crate::routine_id!("ddl-routine-broker-raft-publish-role-cache-1");
        self.cached_term.store(term, Ordering::Release);
        self.cached_role
            .store(Self::role_cache_value(role), Ordering::Release);
    }

    fn publish_runtime_role_cache(&self, runtime: &RaftRuntimeState) {
        crate::routine_id!("ddl-routine-broker-raft-publish-runtime-role-cache-1");
        self.publish_role_cache(runtime.role, runtime.current_term);
    }

    fn leader_peer_hint_from_runtime(runtime: &RaftRuntimeState) -> LeaderPeerHintCache {
        crate::routine_id!("ddl-routine-broker-raft-leader-peer-hint-from-runtime-1");
        let leader_id = runtime.leader_id.clone();
        let leader_peer = leader_id.as_deref().and_then(|id| {
            runtime
                .membership
                .active_peers()
                .into_iter()
                .find(|peer| peer.id == id)
        });
        LeaderPeerHintCache {
            leader_id,
            leader_peer,
        }
    }

    fn publish_leader_peer_hint_cache(&self, runtime: &RaftRuntimeState) -> LeaderPeerHintCache {
        crate::routine_id!("ddl-routine-broker-raft-publish-leader-peer-hint-cache-1");
        let hint = Self::leader_peer_hint_from_runtime(runtime);
        *self.cached_leader_peer.write() = hint.clone();
        hint
    }

    fn note_leader_progress_changed(&self) {
        crate::routine_id!("ddl-routine-broker-raft-progress-changed-1");
        self.leader_progress_generation
            .fetch_add(1, Ordering::AcqRel);
        self.leader_progress_notify.notify_waiters();
    }

    fn leader_progress_generation(&self) -> u64 {
        crate::routine_id!("ddl-routine-broker-raft-progress-generation-1");
        self.leader_progress_generation.load(Ordering::Acquire)
    }

    async fn wait_for_leader_progress_or_sleep(
        &self,
        observed_generation: u64,
        delay: Duration,
    ) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-wait-progress-or-sleep-1");
        if self.leader_progress_generation() != observed_generation {
            return true;
        }
        let notified = self.leader_progress_notify.notified();
        if self.leader_progress_generation() != observed_generation {
            return true;
        }
        tokio::select! {
            _ = notified => self.leader_progress_generation() != observed_generation,
            _ = tokio::time::sleep(delay) => false,
        }
    }

    fn election_loop_action_at(&self, now: Instant) -> RaftElectionLoopAction {
        crate::routine_id!("ddl-routine-broker-raft-election-loop-action-1");
        let runtime = self.runtime.lock();
        self.publish_runtime_role_cache(&runtime);
        if runtime.role == RaftRole::Leader {
            return RaftElectionLoopAction::Heartbeat;
        }
        if now >= runtime.election_deadline {
            return RaftElectionLoopAction::StartElection;
        }
        RaftElectionLoopAction::Sleep(runtime.election_deadline.duration_since(now))
    }

    pub fn is_leader(&self) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-is-leader-1");
        if let Some(runtime) = self.runtime.try_lock() {
            let is_leader = runtime.role == RaftRole::Leader;
            self.publish_runtime_role_cache(&runtime);
            return is_leader;
        }
        self.cached_role.load(Ordering::Acquire) == RAFT_ROLE_CACHE_LEADER
    }

    fn is_leader_in_term(&self, term: u64) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-is-leader-term-1");
        if let Some(runtime) = self.runtime.try_lock() {
            let is_leader_in_term =
                runtime.role == RaftRole::Leader && runtime.current_term == term;
            self.publish_runtime_role_cache(&runtime);
            return is_leader_in_term;
        }
        self.cached_role.load(Ordering::Acquire) == RAFT_ROLE_CACHE_LEADER
            && self.cached_term.load(Ordering::Acquire) == term
    }

    fn replication_peer_config_gate_in_term(
        &self,
        peer: &RaftPeerConfig,
        term: u64,
    ) -> ReplicationPeerGate {
        crate::routine_id!("ddl-routine-broker-raft-replication-peer-config-gate-1");
        let runtime = self.runtime.lock();
        if runtime.role != RaftRole::Leader || runtime.current_term != term {
            return ReplicationPeerGate::NotLeader;
        }
        if runtime.accepts_replication_peer(peer) {
            ReplicationPeerGate::Accepted
        } else {
            ReplicationPeerGate::Removed
        }
    }

    async fn observe_higher_replication_peer_term(
        &self,
        peer: &RaftPeerConfig,
        request_term: u64,
        response_term: u64,
        rpc_kind: &'static str,
        target_index: Option<u64>,
    ) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-observe-higher-replication-peer-term-1");
        if response_term <= request_term {
            return false;
        }
        {
            let runtime = self.runtime.lock();
            if runtime.role != RaftRole::Leader || runtime.current_term != request_term {
                return false;
            }
            if !runtime.accepts_replication_peer(peer) {
                self.telemetry
                    .replication_removed_peer_responses_total
                    .fetch_add(1, Ordering::Relaxed);
                debug!(
                    target: "lmx::raft",
                    node_id = %self.config.node_id,
                    peer = %peer.id,
                    peer_addr = %peer.addr,
                    request_term,
                    response_term,
                    rpc_kind,
                    target_index = ?target_index,
                    "raft ignored higher-term replication response from removed or replaced peer",
                );
                return false;
            }
        }
        self.step_down_blocking(response_term, None).await;
        true
    }

    async fn observe_higher_election_peer_term(
        &self,
        peer: &RaftPeerConfig,
        expected_current_term: u64,
        response_term: u64,
        rpc_kind: &'static str,
    ) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-observe-higher-election-peer-term-1");
        if response_term <= expected_current_term {
            return false;
        }
        {
            let runtime = self.runtime.lock();
            if runtime.current_term != expected_current_term {
                return false;
            }
            if !runtime.accepts_active_peer(peer) {
                self.telemetry
                    .election_removed_peer_responses_total
                    .fetch_add(1, Ordering::Relaxed);
                debug!(
                    target: "lmx::raft",
                    node_id = %self.config.node_id,
                    peer = %peer.id,
                    peer_addr = %peer.addr,
                    expected_current_term,
                    response_term,
                    rpc_kind,
                    "raft ignored higher-term election response from removed or replaced peer",
                );
                return false;
            }
        }
        self.step_down_blocking(response_term, None).await;
        true
    }

    pub fn is_leader_ready(&self) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-is-leader-ready-1");
        let local_peer = self.local_configured_peer();
        let (is_leader, local_is_active, self_is_quorum) = {
            let runtime = self.runtime.lock();
            let self_ack = BTreeSet::from([self.config.node_id.clone()]);
            let local_is_active = runtime.accepts_active_peer(&local_peer);
            (
                runtime.role == RaftRole::Leader,
                local_is_active,
                local_is_active && runtime.membership.quorum_met(&self_ack),
            )
        };
        if !is_leader || !local_is_active {
            return false;
        }
        if self_is_quorum {
            return true;
        }
        self.maintenance.lock().leader_quorum_observed_at.elapsed()
            < self.config.election_timeout_min
    }

    async fn ensure_leader_ready_async(&self) -> Result<(), BrokerRaftError> {
        crate::routine_id!("ddl-routine-broker-raft-ensure-leader-ready-async-1");
        self.apply_visible_durable_commit_index_blocking().await?;
        self.ensure_leader_ready_after_visible_commit_applied()
            .await
    }

    async fn ensure_leader_ready_after_visible_commit_applied(
        &self,
    ) -> Result<(), BrokerRaftError> {
        crate::routine_id!(
            "ddl-routine-broker-raft-ensure-leader-ready-after-visible-commit-applied-1"
        );
        if self.is_leader_ready() {
            return Ok(());
        }
        let should_step_down = {
            let local_peer = self.local_configured_peer();
            let runtime = self.runtime.lock();
            let self_ack = BTreeSet::from([self.config.node_id.clone()]);
            let local_is_active = runtime.accepts_active_peer(&local_peer);
            runtime.role == RaftRole::Leader
                && (!local_is_active
                    || !runtime.membership.quorum_met(&self_ack)
                        && self.maintenance.lock().leader_quorum_observed_at.elapsed()
                            >= self.config.election_timeout_min)
        };
        if should_step_down {
            let term = self.runtime.lock().current_term;
            self.step_down_blocking(term, None).await;
        }
        Err(BrokerRaftError::NotLeader {
            leader_id: self.leader_id(),
            leader_addr: self.leader_addr(),
        })
    }

    pub fn leader_id(&self) -> Option<String> {
        crate::routine_id!("ddl-routine-broker-raft-leader-id-1");
        self.runtime.lock().leader_id.clone()
    }

    fn leader_peer_hint(&self) -> (Option<String>, Option<RaftPeerConfig>) {
        crate::routine_id!("ddl-routine-broker-raft-leader-peer-hint-1");
        let hint = if let Some(runtime) = self.runtime.try_lock() {
            self.publish_leader_peer_hint_cache(&runtime)
        } else {
            self.cached_leader_peer.read().clone()
        };
        (hint.leader_id, hint.leader_peer)
    }

    fn proxy_candidate_peers(
        &self,
        preferred: Option<&RaftPeerConfig>,
        attempts: u64,
    ) -> Vec<RaftPeerConfig> {
        crate::routine_id!("ddl-routine-broker-raft-proxy-candidate-peers-1");
        let mut peers = self
            .active_peers()
            .into_iter()
            .filter(|peer| peer.id != self.config.node_id)
            .collect::<Vec<_>>();
        if peers.len() > 1 {
            let offset = attempts as usize % peers.len();
            peers.rotate_left(offset);
        }
        if let Some(preferred) = preferred {
            if preferred.id != self.config.node_id {
                if let Some(index) = peers.iter().position(|peer| peer.id == preferred.id) {
                    let preferred = peers.remove(index);
                    peers.insert(0, preferred);
                }
            }
        }
        peers
    }

    fn proxy_redirect_peer(
        &self,
        leader_id: Option<&str>,
        leader_addr: Option<&str>,
        reject_peer_id: &str,
    ) -> Option<RaftPeerConfig> {
        crate::routine_id!("ddl-routine-broker-raft-proxy-redirect-peer-1");
        let active_peers = self.active_peers();
        if let Some(leader_id) = leader_id {
            if leader_id == self.config.node_id || leader_id == reject_peer_id {
                return None;
            }
            return active_peers.into_iter().find(|peer| {
                peer.id == leader_id && leader_addr.is_none_or(|addr| peer.addr == addr)
            });
        }
        let leader_addr = leader_addr?;
        active_peers.into_iter().find(|peer| {
            peer.id != self.config.node_id && peer.id != reject_peer_id && peer.addr == leader_addr
        })
    }

    fn proxy_candidate_response_gate(
        &self,
        candidate_peer: &RaftPeerConfig,
    ) -> ProxyCandidateResponseGate {
        crate::routine_id!("ddl-routine-broker-raft-proxy-candidate-response-gate-1");
        let runtime = self.runtime.lock();
        if runtime.role == RaftRole::Leader {
            return ProxyCandidateResponseGate::BecameLeader;
        }
        if runtime.accepts_active_peer(candidate_peer) {
            ProxyCandidateResponseGate::Accepted
        } else {
            ProxyCandidateResponseGate::Removed
        }
    }

