    pub fn progress_snapshot(&self) -> RaftProgressSnapshot {
        crate::routine_id!("ddl-routine-broker-raft-progress-snapshot-1");
        let last_log_index = self.log.last_index();
        let last_log_term = self.log.last_term();
        let (
            role,
            is_leader,
            leader_id,
            current_term,
            commit_index,
            last_applied,
            membership,
            leader_progress,
            staged_learners,
        ) = {
            let runtime = self.runtime.lock();
            let is_leader = runtime.role == RaftRole::Leader;
            (
                raft_role_name(runtime.role),
                is_leader,
                runtime.leader_id.clone(),
                runtime.current_term,
                runtime.commit_index,
                runtime.last_applied,
                runtime.membership.clone(),
                runtime.leader_progress.clone(),
                runtime.staged_learners.clone(),
            )
        };
        let leader_quorum_age_ms = is_leader.then(|| {
            self.maintenance
                .lock()
                .leader_quorum_observed_at
                .elapsed()
                .as_millis() as u64
        });
        let is_leader_ready = self.is_leader_ready();
        let mut peers_by_id = membership
            .active_peers()
            .into_iter()
            .map(|peer| (peer.id.clone(), peer))
            .collect::<BTreeMap<_, _>>();
        peers_by_id.extend(
            staged_learners
                .iter()
                .map(|(id, peer)| (id.clone(), peer.clone())),
        );
        for peer_id in leader_progress.keys() {
            peers_by_id
                .entry(peer_id.clone())
                .or_insert_with(|| RaftPeerConfig {
                    id: peer_id.clone(),
                    addr: String::new(),
                });
        }
        peers_by_id
            .entry(self.config.node_id.clone())
            .or_insert_with(|| RaftPeerConfig {
                id: self.config.node_id.clone(),
                addr: self
                    .config
                    .advertise_addr
                    .clone()
                    .or_else(|| {
                        self.config
                            .bind_addr
                            .as_ref()
                            .map(std::string::ToString::to_string)
                    })
                    .unwrap_or_default(),
            });

        let peers = peers_by_id
            .into_iter()
            .map(|(id, peer)| {
                let is_self = id == self.config.node_id;
                let staged_learner = staged_learners.contains_key(&id);
                let progress = if is_self {
                    Some(RaftPeerProgress {
                        next_index: last_log_index.saturating_add(1),
                        match_index: last_log_index,
                    })
                } else {
                    leader_progress.get(&id).copied()
                };
                let match_index = progress.map(|progress| progress.match_index);
                let trusted_match_index = progress
                    .and_then(|progress| trusted_peer_match_index(progress, last_log_index));
                let next_index = progress.map(|progress| progress.next_index);
                let lag = match (match_index, trusted_match_index) {
                    (Some(_), Some(match_index)) => {
                        Some(last_log_index.saturating_sub(match_index))
                    }
                    (Some(_), None) => Some(last_log_index),
                    (None, None) => None,
                    (None, Some(_)) => None,
                };
                let caught_up = match (match_index, trusted_match_index) {
                    (Some(_), Some(match_index)) => Some(match_index >= last_log_index),
                    (Some(_), None) => Some(false),
                    (None, _) => None,
                };
                RaftPeerProgressSnapshot {
                    id: id.clone(),
                    addr: peer.addr,
                    is_self,
                    voter: !staged_learner && membership.contains_id(&id),
                    staged_learner,
                    membership_role: membership_role_name(&membership, &id, staged_learner),
                    next_index,
                    match_index,
                    lag,
                    caught_up,
                }
            })
            .collect::<Vec<_>>();

        RaftProgressSnapshot {
            node_id: self.config.node_id.clone(),
            role,
            is_leader,
            is_leader_ready,
            leader_id: leader_id.clone(),
            leader_addr: leader_id
                .as_ref()
                .and_then(|id| peers.iter().find(|peer| &peer.id == id))
                .map(|peer| peer.addr.clone()),
            leader_quorum_age_ms,
            leader_quorum_timeout_ms: self.config.election_timeout_min.as_millis() as u64,
            current_term,
            commit_index,
            last_applied,
            last_log_index,
            last_log_term,
            sync_log: self.config.sync_log,
            sync_commit: self.config.sync_commit,
            unsafe_durability: !(self.config.sync_log && self.config.sync_commit),
            membership_joint: membership.is_joint(),
            membership,
            peers,
        }
    }

    pub async fn progress_snapshot_fresh(&self) -> Result<RaftProgressSnapshot, BrokerRaftError> {
        crate::routine_id!("ddl-routine-broker-raft-progress-snapshot-fresh-1");
        self.apply_visible_durable_commit_index_blocking().await?;
        Ok(self.progress_snapshot())
    }

