    fn commit_leader_index_in_term_with_membership(
        &self,
        index: u64,
        term: u64,
        compact_after_apply: bool,
        commit_membership: Option<&RaftMembership>,
    ) -> Result<bool, BrokerRaftError> {
        self.commit_leader_index_in_term_with_membership_control(
            index,
            term,
            compact_after_apply,
            commit_membership,
            true,
        )
    }

    fn commit_leader_index_in_term_with_membership_control(
        &self,
        index: u64,
        term: u64,
        compact_after_apply: bool,
        commit_membership: Option<&RaftMembership>,
        apply_after_commit: bool,
    ) -> Result<bool, BrokerRaftError> {
        crate::routine_id!("ddl-routine-broker-raft-commit-leader-index-1");
        if self.log.term_at(index)? != Some(term) {
            return Ok(false);
        }
        let local_match_index = self.log.last_index();
        let mut committed_from = None;
        let hard_state = {
            let runtime = self.runtime.lock();
            if runtime.role != RaftRole::Leader || runtime.current_term != term {
                return Ok(false);
            }
            if index <= runtime.commit_index {
                None
            } else {
                let membership = commit_membership
                    .cloned()
                    .unwrap_or_else(|| runtime.membership.clone());
                let ack_ids = matched_ids_for_index(
                    &self.config.node_id,
                    local_match_index,
                    &runtime.leader_progress,
                    index,
                );
                if !membership.quorum_met(&ack_ids) {
                    return Ok(false);
                }
                Some(RaftHardState {
                    current_term: runtime.current_term,
                    voted_for: runtime.voted_for.clone(),
                    commit_index: index,
                })
            }
        };
        if let Some(hard_state) = hard_state {
            self.log.write_hard_state(&hard_state)?;
            #[cfg(test)]
            self.run_leader_commit_after_hard_state_write_hook();
            let mut recheck_failure = None;
            {
                let mut runtime = self.runtime.lock();
                if runtime.role != RaftRole::Leader || runtime.current_term != term {
                    recheck_failure = Some((
                        "role-term",
                        runtime.current_term,
                        runtime.role,
                        0,
                        runtime.membership.quorum_size(),
                        runtime.membership.is_joint(),
                    ));
                } else {
                    let membership = commit_membership
                        .cloned()
                        .unwrap_or_else(|| runtime.membership.clone());
                    let ack_ids = matched_ids_for_index(
                        &self.config.node_id,
                        self.log.last_index(),
                        &runtime.leader_progress,
                        index,
                    );
                    if !membership.quorum_met(&ack_ids) {
                        recheck_failure = Some((
                            "quorum",
                            runtime.current_term,
                            runtime.role,
                            ack_ids.len(),
                            membership.quorum_size(),
                            membership.is_joint(),
                        ));
                    } else {
                        let previous_commit = runtime.commit_index;
                        runtime.commit_index = runtime.commit_index.max(index);
                        if runtime.commit_index > previous_commit {
                            committed_from = Some((
                                previous_commit,
                                runtime.commit_index,
                                ack_ids.len(),
                                membership.quorum_size(),
                                membership.is_joint(),
                            ));
                        }
                    }
                }
            }
            if let Some((reason, runtime_term, runtime_role, ack_count, quorum, membership_joint)) =
                recheck_failure
            {
                debug!(
                    target: "lmx::raft",
                    node_id = %self.config.node_id,
                    term,
                    runtime_term,
                    ?runtime_role,
                    commit_index = index,
                    ack_count,
                    quorum,
                    membership_joint,
                    reason,
                    "raft leader commit recheck failed after durable commit write; applying visible durable commit",
                );
                self.apply_visible_durable_commit_index()?;
                return Ok(false);
            }
        }
        if let Some((previous_commit, commit_index, ack_count, quorum, membership_joint)) =
            committed_from
        {
            self.telemetry
                .leader_commit_advancements_total
                .fetch_add(1, Ordering::Relaxed);
            self.telemetry
                .leader_commit_advanced_entries_total
                .fetch_add(
                    commit_index.saturating_sub(previous_commit),
                    Ordering::Relaxed,
                );
            debug!(
                target: "lmx::raft",
                node_id = %self.config.node_id,
                term,
                previous_commit,
                commit_index,
                advanced_entries = commit_index.saturating_sub(previous_commit),
                ack_count,
                quorum,
                membership_joint,
                "raft leader advanced commit index",
            );
        }
        if apply_after_commit {
            self.apply_committed_and_maybe_compact_locked(compact_after_apply, false)?;
        }
        Ok(true)
    }

    fn spawn_post_commit_heartbeat(&self) {
        crate::routine_id!("ddl-routine-broker-raft-post-commit-heartbeat-1");
        if !self.request_post_commit_fanout() {
            return;
        }
        let node = self.clone();
        tokio::spawn(async move {
            node.run_post_commit_fanout().await;
        });
    }

    fn request_post_commit_fanout(&self) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-request-post-commit-fanout-1");
        let mut state = self.post_commit_fanout.lock();
        state.pending = true;
        if state.active {
            false
        } else {
            state.active = true;
            true
        }
    }

    fn take_post_commit_fanout_round(&self) -> bool {
        crate::routine_id!("ddl-routine-broker-raft-take-post-commit-fanout-1");
        let mut state = self.post_commit_fanout.lock();
        if state.pending {
            state.pending = false;
            true
        } else {
            state.active = false;
            false
        }
    }

    async fn run_post_commit_fanout(&self) {
        crate::routine_id!("ddl-routine-broker-raft-run-post-commit-fanout-1");
        while self.take_post_commit_fanout_round() {
            let _commit_guard = self.lock_serialized_commit_lane("post_commit_fanout").await;
            self.telemetry
                .post_commit_fanout_rounds_total
                .fetch_add(1, Ordering::Relaxed);
            if let Err(err) = self.replicate_log_once(None).await {
                self.telemetry
                    .post_commit_fanout_errors_total
                    .fetch_add(1, Ordering::Relaxed);
                debug!(
                    target: "lmx::raft",
                    node_id = %self.config.node_id,
                    error = %err,
                    "post-commit AppendEntries fan-out failed",
                );
            }
        }
    }

