async fn read_raft_frame_bounded<R>(reader: &mut R, max_bytes: usize) -> std::io::Result<String>
where
    R: AsyncBufRead + Unpin,
{
    crate::routine_id!("ddl-routine-broker-raft-read-frame-bounded-1");
    let mut buf = Vec::new();
    loop {
        let chunk = reader.fill_buf().await?;
        if chunk.is_empty() {
            if buf.is_empty() {
                return Err(std::io::Error::new(
                    std::io::ErrorKind::UnexpectedEof,
                    "raft RPC frame ended before any bytes were read",
                ));
            }
            break;
        }
        if let Some(idx) = chunk.iter().position(|byte| *byte == b'\n') {
            let take = idx + 1;
            if buf.len().saturating_add(take) > max_bytes {
                reader.consume(take);
                return Err(std::io::Error::new(
                    std::io::ErrorKind::InvalidData,
                    format!("raft RPC frame exceeds {max_bytes} bytes"),
                ));
            }
            buf.extend_from_slice(&chunk[..take]);
            reader.consume(take);
            break;
        }

        let take = chunk.len();
        if buf.len().saturating_add(take) > max_bytes {
            reader.consume(take);
            return Err(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                format!("raft RPC frame exceeds {max_bytes} bytes"),
            ));
        }
        buf.extend_from_slice(chunk);
        reader.consume(take);
    }

    if buf.ends_with(b"\n") {
        buf.pop();
        if buf.ends_with(b"\r") {
            buf.pop();
        }
    }
    String::from_utf8(buf).map_err(|err| {
        std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            format!("raft RPC frame is not valid UTF-8: {err}"),
        )
    })
}

async fn read_raft_frame_bounded_counted<R>(
    reader: &mut R,
    max_bytes: usize,
    inbound_frame_rejection_counter: &AtomicU64,
) -> std::io::Result<String>
where
    R: AsyncBufRead + Unpin,
{
    crate::routine_id!("ddl-routine-broker-raft-read-frame-bounded-counted-1");
    match read_raft_frame_bounded(reader, max_bytes).await {
        Ok(line) => Ok(line),
        Err(err) => {
            if is_raft_frame_limit_io_error(&err) {
                inbound_frame_rejection_counter.fetch_add(1, Ordering::Relaxed);
            }
            Err(err)
        }
    }
}

async fn wait_for_response(
    rx: &mut tokio::sync::mpsc::UnboundedReceiver<Response>,
    request_uuid: &str,
    wait: Duration,
    keep_polling_until_definitive: bool,
) -> Option<Response> {
    crate::routine_id!("ddl-routine-broker-raft-wait-response-1");
    let timeout = if wait.is_zero() {
        Duration::from_millis(50)
    } else {
        wait
    };
    let deadline = deadline_after(timeout);
    let mut last_match: Option<Response> = None;
    loop {
        let remaining = deadline.saturating_duration_since(tokio::time::Instant::now());
        let res = if remaining.is_zero() {
            rx.try_recv().ok()
        } else {
            tokio::time::timeout(remaining, rx.recv())
                .await
                .ok()
                .flatten()
        };
        match res {
            Some(msg) if msg.correlation_uuid() == request_uuid => {
                let definitive = matches!(
                    &msg,
                    Response::Lock { acquired: true, .. }
                        | Response::CompositeLock { acquired: true, .. }
                        | Response::RegisterReadResult { granted: true, .. }
                        | Response::RegisterWriteResult { granted: true, .. }
                        | Response::Unlock { .. }
                        | Response::EndReadResult { .. }
                        | Response::EndWriteResult { .. }
                        | Response::LockInfo { .. }
                        | Response::LsResult { .. }
                        | Response::Error { .. }
                );
                last_match = Some(msg);
                if definitive || !keep_polling_until_definitive {
                    return last_match;
                }
            }
            Some(_) => continue,
            None => return last_match,
        }
    }
}

fn command_with_deterministic_grant(command: RaftCommand, index: u64) -> RaftCommand {
    crate::routine_id!("ddl-routine-broker-raft-command-deterministic-grant-1");
    match command {
        RaftCommand::ClientRequest {
            client_id,
            request,
            grant,
        } => {
            let grant = grant.or_else(|| deterministic_grant_plan(&request, index));
            RaftCommand::ClientRequest {
                client_id,
                request,
                grant,
            }
        }
        RaftCommand::ClientRequestWithIdentity {
            client_id,
            request,
            grant,
            request_id,
            request_fingerprint,
        } => {
            let grant = grant.or_else(|| deterministic_grant_plan(&request, index));
            RaftCommand::ClientRequestWithIdentity {
                client_id,
                request,
                grant,
                request_id,
                request_fingerprint,
            }
        }
        other => other,
    }
}

fn client_request_identities_from_commands(commands: &[RaftCommand]) -> Vec<(String, String)> {
    crate::routine_id!("ddl-routine-broker-raft-command-request-identities-1");
    commands
        .iter()
        .filter_map(|command| {
            let RaftCommand::ClientRequestWithIdentity {
                request_id,
                request_fingerprint,
                ..
            } = command
            else {
                return None;
            };
            Some((request_id.clone(), request_fingerprint.clone()))
        })
        .collect()
}

fn request_for_ephemeral_wait(mut request: Request, wait: Duration, is_acquire: bool) -> Request {
    crate::routine_id!("ddl-routine-broker-raft-request-ephemeral-wait-1");
    if is_acquire && wait.is_zero() {
        if let Request::Lock { wait, .. } = &mut request {
            *wait = Some(false);
        }
    }
    request
}

fn ensure_supported_raft_client_request(request: &Request) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-supported-client-request-1");
    match request {
        Request::Lock {
            keys: Some(keys), ..
        } => ensure_supported_raft_composite_keys(keys, "lock"),
        Request::Unlock {
            keys: Some(keys), ..
        } => ensure_supported_raft_composite_keys(keys, "unlock"),
        _ => Ok(()),
    }
}

fn ensure_replicable_raft_client_request(request: &Request) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-replicable-client-request-1");
    match request {
        Request::Version { .. } | Request::Auth { .. } | Request::Heartbeat { .. } => {
            Err(BrokerRaftError::UnsupportedClientRequest(format!(
                "{} requests cannot be replicated in the Raft log",
                proxy_request_kind_label(request)
            )))
        }
        _ => ensure_supported_raft_client_request(request),
    }
}

/// Validate a public composite (`keys`) lock/unlock request before it is allowed
/// to reach batching or the replicated log. Composite locking is replicated
/// deterministically (every replica applies the same sorted member order, the
/// same [`deterministic_lock_uuid`], and the same per-key fencing tokens derived
/// from [`deterministic_fencing_seed`]), but admission is bounded to
/// [`RAFT_MAX_COMPOSITE_KEYS`] distinct keys so the token reservation per log
/// index can never overlap the next index's seed. Distinct count mirrors the
/// inner broker, which sorts and dedups member keys before granting.
fn ensure_supported_raft_composite_keys(
    keys: &[String],
    op: &'static str,
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-supported-composite-keys-1");
    if keys.is_empty() {
        return Err(BrokerRaftError::UnsupportedClientRequest(format!(
            "composite {op} requires at least one key"
        )));
    }
    let distinct = keys.iter().collect::<BTreeSet<_>>().len();
    if distinct > RAFT_MAX_COMPOSITE_KEYS {
        return Err(BrokerRaftError::UnsupportedClientRequest(format!(
            "BrokerRaft composite {op} supports at most {RAFT_MAX_COMPOSITE_KEYS} distinct keys; got {distinct}"
        )));
    }
    Ok(())
}

fn request_fingerprint(request: &Request) -> Result<String, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-request-fingerprint-1");
    serde_json::to_string(request)
        .map(|serialized| sha256_hex(serialized.as_bytes()))
        .map_err(BrokerRaftError::from)
}

fn observe_client_response_cache(
    cache: &Arc<Mutex<ClientResponseCacheState>>,
    response: &Response,
) {
    crate::routine_id!("ddl-routine-broker-raft-observe-client-response-cache-1");
    let request_id = response.correlation_uuid();
    let mut cache = cache.lock();
    if let Some(cached) = cache.entries.get_mut(request_id) {
        cached.applied = true;
        cached.response = Some(response.clone());
        cache.order.retain(|existing| existing != request_id);
        cache.order.push_back(request_id.to_string());
    }
}

fn trim_client_response_cache(cache: &mut ClientResponseCacheState, limit: usize) {
    crate::routine_id!("ddl-routine-broker-raft-trim-client-response-cache-1");
    while cache.entries.len() > limit {
        let Some(evict_pos) = cache.order.iter().position(|request_id| {
            cache
                .entries
                .get(request_id)
                .is_none_or(|cached| cached.applied)
        }) else {
            break;
        };
        let Some(oldest) = cache.order.remove(evict_pos) else {
            break;
        };
        cache.entries.remove(&oldest);
    }
}

fn request_is_fail_fast_acquire(request: &Request) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-request-fail-fast-acquire-1");
    matches!(
        request,
        Request::Lock {
            wait: Some(false),
            ..
        }
    )
}

/// Classify an error string returned by a proxied leader as terminal (the
/// request or proxy hop is invalid and re-forwarding cannot help) versus
/// transient (a leadership/transport hiccup worth retrying). NotLeader,
/// quorum/queue pressure, and transport failures are retried within the
/// follower's proxy budget. Matches the `Display` text of the corresponding
/// [`BrokerRaftError`] variants.
fn proxy_error_is_terminal(error: &str) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-proxy-error-terminal-1");
    // BrokerRaftError::IdempotencyKeyConflict
    error.contains("was reused with a different request payload")
        // BrokerRaftError::UnsupportedClientRequest
        || error.contains("unsupported raft client request")
        || error.contains("raft proxy sender")
}

fn proxy_error_is_not_leader(error: &str) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-proxy-error-not-leader-1");
    // BrokerRaftError::NotLeader
    error.contains("raft node is not leader")
}

fn invalid_proxy_client_response_reason(
    request: &Request,
    request_uuid: &str,
    response: &Response,
) -> Option<String> {
    crate::routine_id!("ddl-routine-broker-raft-invalid-proxy-client-response-1");
    if response.correlation_uuid() != request_uuid {
        return Some(format!(
            "proxied response correlation uuid mismatch: expected `{request_uuid}` got `{}`",
            response.correlation_uuid()
        ));
    }
    if proxy_client_response_matches_request(request, response) {
        return None;
    }
    Some(format!(
        "proxied response kind `{}` does not match request kind `{}`",
        proxy_response_kind_label(response),
        proxy_request_kind_label(request)
    ))
}

fn proxy_client_response_matches_request(request: &Request, response: &Response) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-proxy-response-matches-request-1");
    if matches!(response, Response::Error { .. }) {
        return true;
    }
    match request {
        Request::Version { .. } => matches!(response, Response::Version { .. }),
        Request::Auth { .. } => matches!(response, Response::Auth { .. }),
        Request::Lock {
            keys: Some(keys), ..
        } if !keys.is_empty() => matches!(response, Response::CompositeLock { .. }),
        Request::Lock { .. } => matches!(response, Response::Lock { .. }),
        Request::Unlock { .. } => matches!(response, Response::Unlock { .. }),
        Request::RegisterRead { .. } => matches!(response, Response::RegisterReadResult { .. }),
        Request::RegisterWrite { .. } => matches!(response, Response::RegisterWriteResult { .. }),
        Request::EndRead { .. } => matches!(response, Response::EndReadResult { .. }),
        Request::EndWrite { .. } => matches!(response, Response::EndWriteResult { .. }),
        Request::LockInfo { .. } => matches!(response, Response::LockInfo { .. }),
        Request::Ls { .. } => matches!(response, Response::LsResult { .. }),
        Request::Heartbeat { .. } => matches!(response, Response::Ok { .. }),
    }
}

fn proxy_request_kind_label(request: &Request) -> &'static str {
    crate::routine_id!("ddl-routine-broker-raft-proxy-request-kind-label-1");
    match request {
        Request::Version { .. } => "version",
        Request::Auth { .. } => "auth",
        Request::Lock {
            keys: Some(keys), ..
        } if !keys.is_empty() => "compositeLock",
        Request::Lock { .. } => "lock",
        Request::Unlock { .. } => "unlock",
        Request::RegisterRead { .. } => "registerRead",
        Request::RegisterWrite { .. } => "registerWrite",
        Request::EndRead { .. } => "endRead",
        Request::EndWrite { .. } => "endWrite",
        Request::LockInfo { .. } => "lockInfo",
        Request::Ls { .. } => "ls",
        Request::Heartbeat { .. } => "heartbeat",
    }
}

fn proxy_response_kind_label(response: &Response) -> &'static str {
    crate::routine_id!("ddl-routine-broker-raft-proxy-response-kind-label-1");
    match response {
        Response::Version { .. } => "version",
        Response::Auth { .. } => "auth",
        Response::Lock { .. } => "lock",
        Response::CompositeLock { .. } => "compositeLock",
        Response::Unlock { .. } => "unlock",
        Response::RegisterReadResult { .. } => "registerReadResult",
        Response::RegisterWriteResult { .. } => "registerWriteResult",
        Response::EndReadResult { .. } => "endReadResult",
        Response::EndWriteResult { .. } => "endWriteResult",
        Response::LockInfo { .. } => "lockInfo",
        Response::LsResult { .. } => "lsResult",
        Response::Reelection { .. } => "reelection",
        Response::Error { .. } => "error",
        Response::Ok { .. } => "ok",
    }
}

fn deterministic_grant_plan(request: &Request, index: u64) -> Option<RaftGrantPlan> {
    crate::routine_id!("ddl-routine-broker-raft-deterministic-grant-plan-1");
    if !request_can_grant(request) {
        return None;
    }
    Some(RaftGrantPlan {
        lock_uuid: Some(deterministic_lock_uuid(index)),
        fencing_seed: Some(deterministic_fencing_seed(index)),
    })
}

fn request_can_grant(request: &Request) -> bool {
    crate::routine_id!("ddl-routine-broker-raft-request-can-grant-1");
    matches!(
        request,
        Request::Lock { .. } | Request::RegisterRead { .. } | Request::RegisterWrite { .. }
    )
}

fn deterministic_lock_uuid(index: u64) -> String {
    crate::routine_id!("ddl-routine-broker-raft-deterministic-lock-uuid-1");
    format!("raft-{index:020}")
}

fn deterministic_fencing_seed(index: u64) -> u64 {
    crate::routine_id!("ddl-routine-broker-raft-deterministic-fencing-seed-1");
    RAFT_FENCING_TOKEN_BASE
        .saturating_add(index.saturating_mul(MAX_COMPOSITE_KEYS.saturating_add(1) as u64))
}

fn granted_lock_uuid(resp: &Response) -> Option<String> {
    crate::routine_id!("ddl-routine-broker-raft-granted-lock-uuid-1");
    match resp {
        Response::Lock {
            acquired: true,
            lock_uuid: Some(u),
            ..
        }
        | Response::CompositeLock {
            acquired: true,
            lock_uuid: Some(u),
            ..
        }
        | Response::RegisterReadResult {
            granted: true,
            lock_uuid: Some(u),
            ..
        }
        | Response::RegisterWriteResult {
            granted: true,
            lock_uuid: Some(u),
            ..
        } => Some(u.clone()),
        _ => None,
    }
}

fn read_snapshot_file(path: &Path) -> Result<Option<RaftSnapshotFile>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-snapshot-file-1");
    let Some(file) = open_raft_json_file(path, "snapshot file")? else {
        return Ok(None);
    };
    let mut snapshot: RaftSnapshotFile = serde_json::from_reader(file)?;
    if let Some(expected) = snapshot.metadata.payload_sha256.as_deref() {
        let verified = verify_snapshot_payload_checksum(
            snapshot.metadata.last_included_index,
            &snapshot.payload,
            Some(expected.to_string()),
        )?;
        snapshot.metadata.payload_sha256 = Some(verified);
    }
    Ok(Some(snapshot))
}

fn raft_json_file_metadata(
    path: &Path,
    label: &'static str,
) -> Result<Option<fs::Metadata>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-json-file-metadata-1");
    let metadata = match fs::symlink_metadata(path) {
        Ok(metadata) => metadata,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => return Err(err.into()),
    };
    if metadata.file_type().is_symlink() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft {label} path {} is a symlink; remove it manually after confirming no Raft writer is active",
            path.display()
        )));
    }
    if !metadata.is_file() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft {label} path {} is not a regular file",
            path.display()
        )));
    }
    Ok(Some(metadata))
}

fn open_raft_json_file(path: &Path, label: &'static str) -> Result<Option<File>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-open-json-file-1");
    if raft_json_file_metadata(path, label)?.is_none() {
        return Ok(None);
    }
    let mut options = OpenOptions::new();
    options.read(true).truncate(false);
    #[cfg(unix)]
    {
        options.custom_flags(regular_state_file_open_flags());
    }
    let file = options.open(path).map_err(BrokerRaftError::Io)?;
    opened_regular_file_metadata(&file, path, &format!("raft {label}"))?;
    Ok(Some(file))
}

fn snapshot_payload_sha256(payload: &serde_json::Value) -> Result<String, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-snapshot-sha256-1");
    let bytes = serde_json::to_vec(payload)?;
    Ok(sha256_hex(&bytes))
}

fn verify_snapshot_payload_checksum(
    index: u64,
    payload: &serde_json::Value,
    expected: Option<String>,
) -> Result<String, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-verify-snapshot-sha256-1");
    let expected = expected.ok_or(BrokerRaftError::SnapshotChecksumMissing { index })?;
    let actual = snapshot_payload_sha256(payload)?;
    if !actual.eq_ignore_ascii_case(&expected) {
        return Err(BrokerRaftError::SnapshotChecksumMismatch {
            index,
            expected,
            actual,
        });
    }
    Ok(actual)
}

fn validate_existing_snapshot_matches_install(
    snapshot_path: &Path,
    existing: &RaftSnapshotMetadata,
    incoming_term: u64,
    incoming_payload_sha256: &str,
) -> Result<(), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-existing-snapshot-install-1");
    if existing.last_included_term != incoming_term {
        return Err(BrokerRaftError::InvalidLog(format!(
            "local snapshot term {} at index {} conflicts with InstallSnapshot term {incoming_term}",
            existing.last_included_term, existing.last_included_index
        )));
    }

    let existing_payload_sha256 = match existing.payload_sha256.as_deref() {
        Some(checksum) => checksum.to_string(),
        None => {
            let snapshot = read_snapshot_file(snapshot_path)?.ok_or_else(|| {
                BrokerRaftError::InvalidLog(format!(
                    "local snapshot metadata at index {} has no checksum and snapshot file is missing",
                    existing.last_included_index
                ))
            })?;
            if snapshot.metadata.last_included_index != existing.last_included_index
                || snapshot.metadata.last_included_term != existing.last_included_term
            {
                return Err(BrokerRaftError::InvalidLog(format!(
                    "local snapshot metadata changed while validating InstallSnapshot at index {}",
                    existing.last_included_index
                )));
            }
            snapshot_payload_sha256(&snapshot.payload)?
        }
    };

    if !existing_payload_sha256.eq_ignore_ascii_case(incoming_payload_sha256) {
        return Err(BrokerRaftError::InvalidLog(format!(
            "local snapshot payload checksum at index {} conflicts with InstallSnapshot payload checksum",
            existing.last_included_index
        )));
    }

    Ok(())
}

fn read_verified_snapshot_payload_file(
    index: u64,
    path: &Path,
    expected: Option<String>,
) -> Result<serde_json::Value, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-verified-snapshot-payload-file-1");
    let expected = expected.ok_or(BrokerRaftError::SnapshotChecksumMissing { index })?;
    let bytes = read_snapshot_part_file(path)?;
    let actual = sha256_hex(&bytes);
    if !actual.eq_ignore_ascii_case(&expected) {
        return Err(BrokerRaftError::SnapshotChecksumMismatch {
            index,
            expected,
            actual,
        });
    }
    Ok(serde_json::from_slice(&bytes)?)
}

fn decode_snapshot_chunk(data: &str) -> Result<Vec<u8>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-decode-snapshot-chunk-1");
    BASE64
        .decode(data.as_bytes())
        .map_err(|err| BrokerRaftError::Rpc(format!("invalid snapshot chunk encoding: {err}")))
}

fn snapshot_transfer_key(
    leader_id: &str,
    last_included_index: u64,
    last_included_term: u64,
    payload_sha256: &str,
) -> String {
    crate::routine_id!("ddl-routine-broker-raft-snapshot-transfer-key-1");
    format!("{leader_id}:{last_included_index}:{last_included_term}:{payload_sha256}")
}

fn staged_snapshot_chunk_matches(
    path: &Path,
    offset: u64,
    chunk: &[u8],
) -> Result<bool, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-staged-snapshot-chunk-matches-1");
    let end = offset
        .checked_add(chunk.len() as u64)
        .ok_or_else(|| BrokerRaftError::Rpc("snapshot duplicate chunk range overflowed".into()))?;
    let mut file = open_snapshot_part_file(path, true, false, false)?;
    let file_len = file.metadata()?.len();
    if file_len < end {
        return Err(BrokerRaftError::Rpc(format!(
            "snapshot transfer file length mismatch while verifying duplicate chunk; expected at least {end} bytes actual={file_len}"
        )));
    }
    file.seek(SeekFrom::Start(offset))?;
    let mut staged = vec![0; chunk.len()];
    file.read_exact(&mut staged)?;
    Ok(staged == chunk)
}

fn read_snapshot_part_file(path: &Path) -> Result<Vec<u8>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-snapshot-part-file-1");
    let mut file = open_snapshot_part_file(path, true, false, false)?;
    let mut bytes = Vec::new();
    file.read_to_end(&mut bytes)?;
    Ok(bytes)
}

fn snapshot_part_file_metadata(path: &Path) -> Result<Option<fs::Metadata>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-snapshot-part-metadata-1");
    let metadata = match fs::symlink_metadata(path) {
        Ok(metadata) => metadata,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => return Err(err.into()),
    };
    if metadata.file_type().is_symlink() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft InstallSnapshot part path {} is a symlink; remove it manually after confirming no Raft writer is active",
            path.display()
        )));
    }
    if !metadata.is_file() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft InstallSnapshot part path {} is not a regular file",
            path.display()
        )));
    }
    Ok(Some(metadata))
}

fn open_snapshot_part_file(
    path: &Path,
    read: bool,
    write: bool,
    create: bool,
) -> Result<File, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-open-snapshot-part-file-1");
    let _existing = snapshot_part_file_metadata(path)?;
    let mut options = OpenOptions::new();
    options
        .read(read)
        .write(write)
        .create(create)
        .truncate(false);
    #[cfg(unix)]
    {
        options.custom_flags(regular_state_file_open_flags());
    }
    let file = options.open(path).map_err(BrokerRaftError::Io)?;
    opened_regular_file_metadata(&file, path, "raft InstallSnapshot part")?;
    Ok(file)
}

fn sha256_hex(bytes: &[u8]) -> String {
    crate::routine_id!("ddl-routine-broker-raft-sha256-hex-1");
    let digest = Sha256::digest(bytes);
    hex_encode(&digest)
}

fn hex_encode(bytes: &[u8]) -> String {
    crate::routine_id!("ddl-routine-broker-raft-hex-encode-1");
    const HEX: &[u8; 16] = b"0123456789abcdef";
    let mut out = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        out.push(HEX[(byte >> 4) as usize] as char);
        out.push(HEX[(byte & 0x0f) as usize] as char);
    }
    out
}

#[cfg(test)]
fn read_hard_state(path: &Path) -> Result<RaftHardState, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-hard-state-file-1");
    Ok(read_hard_state_with_commit_slots(path, None)?.0)
}

fn read_hard_state_with_commit_slots(
    path: &Path,
    telemetry: Option<&BrokerRaftTelemetry>,
) -> Result<(RaftHardState, u64), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-hard-state-with-commit-slots-1");
    let mut hard_state = read_hard_state_json(path)?;
    let (commit_slot, generation) = read_hard_state_commit_slots(
        &hard_state_commit_path(path),
        hard_state.current_term,
        telemetry,
    )?;
    if let Some(commit_slot) = commit_slot {
        if commit_slot.commit_index > hard_state.commit_index {
            if let Some(telemetry) = telemetry {
                telemetry
                    .hard_state_commit_slot_recoveries_total
                    .fetch_add(1, Ordering::Relaxed);
            }
        }
        hard_state.commit_index = hard_state.commit_index.max(commit_slot.commit_index);
    }
    Ok((hard_state, generation))
}

fn read_hard_state_json(path: &Path) -> Result<RaftHardState, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-hard-state-json-1");
    let Some(file) = open_raft_json_file(path, "hard-state JSON")? else {
        return Ok(RaftHardState::default());
    };
    Ok(serde_json::from_reader(file)?)
}

fn hard_state_commit_path(hard_state_path: &Path) -> PathBuf {
    crate::routine_id!("ddl-routine-broker-raft-hard-state-commit-path-1");
    hard_state_path.with_file_name(HARD_STATE_COMMIT_FILE)
}

fn hard_state_commit_checksum(generation: u64, current_term: u64, commit_index: u64) -> String {
    crate::routine_id!("ddl-routine-broker-raft-hard-state-commit-checksum-1");
    sha256_hex(format!("{generation}:{current_term}:{commit_index}").as_bytes())
}

fn hard_state_commit_slot_offset(generation: u64) -> u64 {
    crate::routine_id!("ddl-routine-broker-raft-hard-state-commit-slot-offset-1");
    (generation.saturating_sub(1) % HARD_STATE_COMMIT_SLOTS) * HARD_STATE_COMMIT_SLOT_BYTES as u64
}

fn hard_state_commit_slot_record(
    generation: u64,
    current_term: u64,
    commit_index: u64,
) -> RaftHardStateCommitSlot {
    crate::routine_id!("ddl-routine-broker-raft-hard-state-commit-slot-record-1");
    RaftHardStateCommitSlot {
        generation,
        current_term,
        commit_index,
        checksum: hard_state_commit_checksum(generation, current_term, commit_index),
    }
}

fn validate_hard_state_commit_slot(
    slot: RaftHardStateCommitSlot,
) -> Result<RaftHardStateCommitSlot, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-validate-hard-state-commit-slot-1");
    if slot.generation == 0 {
        return Err(BrokerRaftError::InvalidLog(
            "raft hard-state commit slot generation must start at 1".into(),
        ));
    }
    let expected =
        hard_state_commit_checksum(slot.generation, slot.current_term, slot.commit_index);
    if slot.checksum != expected {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft hard-state commit slot generation {} has checksum {}, expected {}",
            slot.generation, slot.checksum, expected
        )));
    }
    Ok(slot)
}

fn read_hard_state_commit_slots(
    path: &Path,
    max_current_term: u64,
    telemetry: Option<&BrokerRaftTelemetry>,
) -> Result<(Option<RaftHardStateCommitSlot>, u64), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-read-hard-state-commit-slots-1");
    if hard_state_commit_sidecar_metadata(path)?.is_none() {
        return Ok((None, 0));
    }
    let mut file = open_hard_state_commit_sidecar_file(path, true, false, false)?;
    let file_len = file.metadata()?.len();
    let mut bytes = Vec::with_capacity(
        file_len
            .min(HARD_STATE_COMMIT_FILE_BYTES as u64)
            .try_into()
            .unwrap_or(HARD_STATE_COMMIT_FILE_BYTES),
    );
    std::io::Read::by_ref(&mut file)
        .take(HARD_STATE_COMMIT_FILE_BYTES as u64)
        .read_to_end(&mut bytes)?;
    if file_len > HARD_STATE_COMMIT_FILE_BYTES as u64 {
        truncate_oversized_hard_state_commit_slots(path, file_len, telemetry);
    }
    let mut slots = Vec::<RaftHardStateCommitSlot>::new();
    for slot_id in 0..HARD_STATE_COMMIT_SLOTS {
        let start = slot_id as usize * HARD_STATE_COMMIT_SLOT_BYTES;
        if start >= bytes.len() {
            continue;
        }
        let end = (start + HARD_STATE_COMMIT_SLOT_BYTES).min(bytes.len());
        let raw = trim_hard_state_commit_slot_bytes(&bytes[start..end]);
        if raw.is_empty() {
            continue;
        }
        let slot = match serde_json::from_slice(raw)
            .map_err(BrokerRaftError::from)
            .and_then(validate_hard_state_commit_slot)
        {
            Ok(slot) => slot,
            Err(err) => {
                if let Some(telemetry) = telemetry {
                    telemetry
                        .hard_state_commit_slot_invalid_recoveries_total
                        .fetch_add(1, Ordering::Relaxed);
                }
                warn!(
                    target: "lmx::raft",
                    path = %path.display(),
                    slot_id,
                    error = %err,
                    "ignored invalid raft hard-state commit slot during recovery",
                );
                continue;
            }
        };
        if slot.current_term > max_current_term {
            if let Some(telemetry) = telemetry {
                telemetry
                    .hard_state_commit_slot_invalid_recoveries_total
                    .fetch_add(1, Ordering::Relaxed);
            }
            warn!(
                target: "lmx::raft",
                path = %path.display(),
                slot_id,
                slot_term = slot.current_term,
                durable_term = max_current_term,
                "ignored raft hard-state commit slot from a future term during recovery",
            );
            continue;
        }
        slots.push(slot);
    }
    slots.sort_by_key(|slot| slot.generation);
    let mut best = None::<RaftHardStateCommitSlot>;
    for slot in slots {
        if best
            .as_ref()
            .is_some_and(|current| slot.commit_index < current.commit_index)
        {
            if let Some(telemetry) = telemetry {
                telemetry
                    .hard_state_commit_slot_invalid_recoveries_total
                    .fetch_add(1, Ordering::Relaxed);
            }
            warn!(
                target: "lmx::raft",
                path = %path.display(),
                slot_generation = slot.generation,
                slot_commit_index = slot.commit_index,
                previous_commit_index = best.as_ref().map(|current| current.commit_index).unwrap_or(0),
                "ignored raft hard-state commit slot that regressed commit index during recovery",
            );
            continue;
        }
        best = Some(slot);
    }
    let generation = best.as_ref().map(|slot| slot.generation).unwrap_or(0);
    Ok((best, generation))
}

fn truncate_oversized_hard_state_commit_slots(
    path: &Path,
    file_len: u64,
    telemetry: Option<&BrokerRaftTelemetry>,
) {
    crate::routine_id!("ddl-routine-broker-raft-truncate-oversized-hard-state-commit-slots-1");
    match open_hard_state_commit_sidecar_file(path, false, true, false).and_then(|file| {
        file.set_len(HARD_STATE_COMMIT_FILE_BYTES as u64)?;
        file.sync_data().map_err(BrokerRaftError::Io)
    }) {
        Ok(()) => {
            if let Some(telemetry) = telemetry {
                telemetry
                    .hard_state_commit_slot_truncations_total
                    .fetch_add(1, Ordering::Relaxed);
            }
            warn!(
                target: "lmx::raft",
                path = %path.display(),
                file_len,
                max_len = HARD_STATE_COMMIT_FILE_BYTES,
                "truncated oversized raft hard-state commit slot sidecar during recovery",
            );
        }
        Err(err) => {
            if let Some(telemetry) = telemetry {
                telemetry
                    .hard_state_commit_slot_truncation_errors_total
                    .fetch_add(1, Ordering::Relaxed);
            }
            warn!(
                target: "lmx::raft",
                path = %path.display(),
                file_len,
                max_len = HARD_STATE_COMMIT_FILE_BYTES,
                error = %err,
                "failed to truncate oversized raft hard-state commit slot sidecar during recovery",
            );
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct FileIdentity {
    #[cfg(unix)]
    dev: u64,
    #[cfg(unix)]
    ino: u64,
    #[cfg(not(unix))]
    len: u64,
}

fn file_identity(metadata: &fs::Metadata) -> FileIdentity {
    crate::routine_id!("ddl-routine-broker-raft-file-identity-1");
    FileIdentity {
        #[cfg(unix)]
        dev: metadata.dev(),
        #[cfg(unix)]
        ino: metadata.ino(),
        #[cfg(not(unix))]
        len: metadata.len(),
    }
}

fn cached_hard_state_commit_file_is_current(
    cached: &CachedHardStateCommitFile,
    path: &Path,
) -> Result<bool, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-cached-commit-file-current-1");
    let Some(metadata) = hard_state_commit_sidecar_metadata(path)? else {
        return Ok(false);
    };
    Ok(file_identity(&metadata) == cached.identity)
}

fn open_hard_state_commit_file(
    path: &Path,
    telemetry: Option<&BrokerRaftTelemetry>,
) -> Result<(CachedHardStateCommitFile, bool), BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-open-commit-slot-file-1");
    let created = hard_state_commit_sidecar_metadata(path)?.is_none();
    let file = open_hard_state_commit_sidecar_file(path, false, true, true)?;
    let metadata = opened_regular_file_metadata(&file, path, "raft hard-state commit sidecar")?;
    if metadata.len() != HARD_STATE_COMMIT_FILE_BYTES as u64 {
        file.set_len(HARD_STATE_COMMIT_FILE_BYTES as u64)?;
    }
    let identity = file_identity(&file.metadata()?);
    if let Some(telemetry) = telemetry {
        telemetry
            .hard_state_commit_slot_file_opens_total
            .fetch_add(1, Ordering::Relaxed);
    }
    Ok((CachedHardStateCommitFile { file, identity }, created))
}

fn hard_state_commit_sidecar_metadata(
    path: &Path,
) -> Result<Option<fs::Metadata>, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-commit-sidecar-metadata-1");
    let metadata = match fs::symlink_metadata(path) {
        Ok(metadata) => metadata,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => return Err(err.into()),
    };
    if metadata.file_type().is_symlink() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft hard-state commit sidecar path {} is a symlink; remove it manually after confirming no Raft writer is active",
            path.display()
        )));
    }
    if !metadata.is_file() {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft hard-state commit sidecar path {} is not a regular file",
            path.display()
        )));
    }
    Ok(Some(metadata))
}

fn open_hard_state_commit_sidecar_file(
    path: &Path,
    read: bool,
    write: bool,
    create: bool,
) -> Result<File, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-open-commit-sidecar-file-1");
    let mut options = OpenOptions::new();
    options
        .read(read)
        .write(write)
        .create(create)
        .truncate(false);
    #[cfg(unix)]
    {
        options.custom_flags(regular_state_file_open_flags());
    }
    let file = options.open(path).map_err(BrokerRaftError::Io)?;
    opened_regular_file_metadata(&file, path, "raft hard-state commit sidecar")?;
    Ok(file)
}

#[cfg(test)]
fn write_hard_state_commit_slot(
    path: &Path,
    generation: u64,
    current_term: u64,
    commit_index: u64,
) -> Result<u64, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-write-hard-state-commit-slot-1");
    let mut cached = None;
    write_hard_state_commit_slot_with_cache(
        path,
        &mut cached,
        generation,
        current_term,
        commit_index,
        true,
        None,
    )
}

fn write_hard_state_commit_slot_with_cache(
    path: &Path,
    cached: &mut Option<CachedHardStateCommitFile>,
    generation: u64,
    current_term: u64,
    commit_index: u64,
    sync_commit: bool,
    telemetry: Option<&BrokerRaftTelemetry>,
) -> Result<u64, BrokerRaftError> {
    crate::routine_id!("ddl-routine-broker-raft-write-hard-state-commit-slot-1");
    if generation == 0 {
        return Err(BrokerRaftError::InvalidLog(
            "raft hard-state commit slot generation must start at 1".into(),
        ));
    }
    let slot = hard_state_commit_slot_record(generation, current_term, commit_index);
    let mut body = serde_json::to_vec(&slot)?;
    body.push(b'\n');
    if body.len() > HARD_STATE_COMMIT_SLOT_BYTES {
        return Err(BrokerRaftError::InvalidLog(format!(
            "raft hard-state commit slot needs {} bytes, exceeding fixed slot size {}",
            body.len(),
            HARD_STATE_COMMIT_SLOT_BYTES
        )));
    }
    body.resize(HARD_STATE_COMMIT_SLOT_BYTES, b' ');
    let result = (|| {
        let mut created = false;
        match cached.as_ref() {
            Some(file) if cached_hard_state_commit_file_is_current(file, path)? => {}
            Some(_) | None => {
                *cached = None;
                let (file, was_created) = open_hard_state_commit_file(path, telemetry)?;
                *cached = Some(file);
                created = was_created;
            }
        }
        let file = &mut cached
            .as_mut()
            .ok_or_else(|| {
                BrokerRaftError::Rpc("raft hard-state commit sidecar cache was empty".into())
            })?
            .file;
        file.seek(SeekFrom::Start(hard_state_commit_slot_offset(generation)))?;
        file.write_all(&body)?;
        file.flush()?;
        if sync_commit {
            file.sync_data()?;
        }
        if created && sync_commit {
            if let Some(parent) = path.parent() {
                sync_dir(parent)?;
            }
        }
        Ok(HARD_STATE_COMMIT_SLOT_BYTES as u64)
    })();
    if result.is_err() {
        *cached = None;
    }
    result
}

