    #[test]
    fn broker_open_rejects_second_live_data_dir_owner_and_releases_on_drop() {
        let dir = temp_dir("raft-open-data-dir-lock");
        let mut cfg = test_raft_config(dir.clone());
        cfg.data_dir_lock = true;

        let raft = BrokerRaft::open(cfg.clone()).expect("open locked raft");
        assert!(
            dir.join(DATA_DIR_LOCK_FILE).exists(),
            "open should create the advisory lock file"
        );
        let duplicate = BrokerRaft::open(cfg.clone());
        let err = match duplicate {
            Ok(_) => panic!("second live BrokerRaft open on the same data_dir must fail"),
            Err(err) => err,
        };
        assert!(
            matches!(&err, BrokerRaftError::InvalidConfig(message) if message.contains("data_dir") && message.contains("locked")),
            "duplicate open should report a locked data_dir: {err:?}"
        );

        let clone = raft.clone();
        drop(raft);
        let still_locked = BrokerRaft::open(cfg.clone());
        assert!(
            matches!(still_locked, Err(BrokerRaftError::InvalidConfig(_))),
            "a cloned live BrokerRaft handle should keep the data_dir lock"
        );
        drop(clone);

        let reopened = BrokerRaft::open(cfg).expect("reopen after dropping lock owner");
        drop(reopened);
        let _ = fs::remove_dir_all(dir);
    }

    #[cfg(unix)]
    #[test]
    fn broker_open_data_dir_lock_does_not_follow_lock_symlink() {
        use std::os::unix::fs as unix_fs;

        let dir = temp_dir("raft-open-data-dir-lock-symlink");
        fs::create_dir_all(&dir).expect("create raft dir");
        let mut cfg = test_raft_config(dir.clone());
        cfg.data_dir_lock = true;
        let lock_path = dir.join(DATA_DIR_LOCK_FILE);
        let target = dir.join("lock-symlink-target");
        fs::write(&target, b"do not truncate").expect("write symlink target");
        unix_fs::symlink(&target, &lock_path).expect("create lock symlink");

        let err = match BrokerRaft::open(cfg.clone()) {
            Ok(_) => panic!("BrokerRaft open must reject a symlinked data-dir lock path"),
            Err(err) => err,
        };

        assert!(
            matches!(&err, BrokerRaftError::InvalidLog(message) if message.contains("data-dir lock") && message.contains("symlink")),
            "unexpected lock symlink error: {err:?}"
        );
        assert_eq!(
            fs::read(&target).expect("read symlink target"),
            b"do not truncate"
        );
        assert!(
            fs::symlink_metadata(&lock_path)
                .expect("lock symlink metadata")
                .file_type()
                .is_symlink(),
            "failed open should leave unexpected lock symlink for operator cleanup"
        );

        fs::remove_file(&lock_path).expect("remove lock symlink");
        let reopened =
            BrokerRaft::open(cfg).expect("lock registry should be released after failure");
        drop(reopened);

        let _ = fs::remove_dir_all(dir);
    }

