    #[test]
    fn membership_validation_rejects_duplicates_and_allows_even_configs() {
        let duplicate = validate_membership_peers(vec![
            test_peer("n1", 7980),
            test_peer("n1", 7981),
            test_peer("n3", 7982),
        ]);
        assert!(matches!(duplicate, Err(BrokerRaftError::InvalidConfig(_))));

        let even = validate_membership_peers(vec![
            test_peer("n1", 7980),
            test_peer("n2", 7981),
            test_peer("n3", 7982),
            test_peer("n4", 7983),
        ]);
        assert_eq!(even.expect("four-voter membership is valid").len(), 4);

        let duplicate_membership = validate_raft_membership(duplicate_peer_membership());
        assert!(matches!(
            duplicate_membership,
            Err(BrokerRaftError::InvalidConfig(_))
        ));

        let invalid_joint = validate_raft_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                test_peer("n1", 7980),
                test_peer("n1", 7990),
                test_peer("n3", 7982),
            ],
        });
        assert!(matches!(
            invalid_joint,
            Err(BrokerRaftError::InvalidConfig(_))
        ));

        let colliding_peer_id = colliding_peer_id_for_prefix("n1");
        let invalid_joint_prefix = validate_raft_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                RaftPeerConfig {
                    id: colliding_peer_id,
                    addr: "127.0.0.1:7990".into(),
                },
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
        });
        assert!(matches!(
            invalid_joint_prefix,
            Err(BrokerRaftError::InvalidConfig(_))
        ));

        let invalid_joint_cross_addr = validate_raft_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                test_peer("n1", 7980),
                RaftPeerConfig {
                    id: "n4".into(),
                    addr: "127.0.0.1:7981".into(),
                },
                test_peer("n5", 7984),
            ],
        });
        assert!(matches!(
            invalid_joint_cross_addr,
            Err(BrokerRaftError::InvalidConfig(message))
                if message.contains("shared by peer `n2`")
                    && message.contains("peer `n4`")
        ));

        validate_raft_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                test_peer("n1", 7980),
                RaftPeerConfig {
                    id: "n2".into(),
                    addr: "127.0.0.1:8999".into(),
                },
                test_peer("n4", 7983),
            ],
        })
        .expect("same peer id may change address during joint membership");
    }

