    #[test]
    fn apply_membership_clears_peer_state_when_local_node_is_removed() {
        let dir = temp_dir("raft-membership-removes-local-node");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.voted_for = Some("n1".into());
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: 4,
                    match_index: 3,
                },
            );
            runtime.staged_learners.insert(
                "n4".into(),
                RaftPeerConfig {
                    id: "n4".into(),
                    addr: "127.0.0.1:7983".into(),
                },
            );
        }
        {
            let mut connections = raft.rpc_connections.lock();
            connections.insert(
                "n2".into(),
                Arc::new(AsyncMutex::new(RaftRpcConnection::default())),
            );
            connections.insert(
                "n4".into(),
                Arc::new(AsyncMutex::new(RaftRpcConnection::default())),
            );
        }

        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n2", 7981),
            test_peer("n3", 7982),
            test_peer("n4", 7983),
        ]))
        .expect("apply membership removing local node");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.role, RaftRole::Follower);
            assert_eq!(runtime.leader_id, None);
            assert_eq!(runtime.voted_for, None);
            assert!(runtime.leader_progress.is_empty());
            assert!(runtime.staged_learners.is_empty());
            assert!(!runtime.membership.contains_id("n1"));
        }
        assert!(raft.rpc_connections.lock().is_empty());

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn local_client_request_guard_rejects_removed_or_joint_old_only_node() {
        let dir = temp_dir("raft-local-client-removed-guard");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");

        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n2", 7981),
            test_peer("n3", 7982),
            test_peer("n4", 7983),
        ]))
        .expect("apply membership removing local node");
        assert_eq!(
            raft.local_client_request_rejection_reason(),
            Some("removed-voter")
        );

        raft.apply_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                test_peer("n2", 7981),
                test_peer("n3", 7982),
                test_peer("n4", 7983),
            ],
        })
        .expect("apply joint membership removing local node from target config");
        assert_eq!(
            raft.local_client_request_rejection_reason(),
            Some("joint-old-only")
        );

        raft.apply_membership(RaftMembership::Joint {
            old_peers: vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ],
            new_peers: vec![
                test_peer("n1", 7980),
                test_peer("n3", 7982),
                test_peer("n4", 7983),
            ],
        })
        .expect("apply joint membership retaining local node in target config");
        assert_eq!(raft.local_client_request_rejection_reason(), None);

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn local_client_request_guard_rejects_public_request_without_proxy_error() {
        let dir = temp_dir("raft-local-client-removed-public-reject");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");

        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n2", 7981),
            test_peer("n3", 7982),
            test_peer("n4", 7983),
        ]))
        .expect("apply membership removing local node");

        let err = raft
            .run_ephemeral(
                single_lock_request("removed-public-lock", "removed-public-key"),
                "removed-public-lock",
                Duration::ZERO,
                true,
            )
            .await
            .expect_err("removed local voter must reject public client request");

        assert!(matches!(err, BrokerRaftError::NotLeader { .. }));
        assert!(raft.log.read_entries().expect("entries").is_empty());
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.client_removed_member_rejections_total, 1);
        assert_eq!(telemetry.proxy_requests_forwarded_total, 0);
        assert_eq!(telemetry.proxy_requests_handled_total, 0);
        assert_eq!(telemetry.proxy_request_errors_total, 0);
        assert!(raft
            .raft_metrics_text()
            .contains("dd_rust_network_mutex_raft_client_removed_member_rejections_total 1"));

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn local_identity_uses_configured_addr_and_treats_replaced_self_addr_as_removed() {
        let dir = temp_dir("raft-local-identity-configured-addr");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");

        raft.apply_membership(RaftMembership::from_simple(vec![
            RaftPeerConfig {
                id: "n1".into(),
                addr: "127.0.0.1:8999".into(),
            },
            test_peer("n2", 7981),
            test_peer("n3", 7982),
        ]))
        .expect("replace local voter address");

        let local_peer = raft.local_outbound_peer();
        assert_eq!(local_peer.id, "n1");
        assert_eq!(
            local_peer.addr, "127.0.0.1:7980",
            "outbound RPC identity must use the configured local address, not the replacement membership row"
        );
        {
            let runtime = raft.runtime.lock();
            assert!(runtime.membership.contains_id("n1"));
            assert!(!runtime.accepts_active_peer(&local_peer));
            assert!(runtime.local_voter_seen);
            assert_eq!(runtime.role, RaftRole::Follower);
        }
        assert_eq!(
            raft.local_client_request_rejection_reason(),
            Some("removed-voter")
        );
        assert!(
            raft.begin_pre_vote_round()
                .expect("pre-vote round check")
                .is_none(),
            "a process whose configured local address was replaced must not start elections"
        );
        {
            let mut runtime = raft.runtime.lock();
            runtime.role = RaftRole::Leader;
            runtime.current_term = 4;
            runtime.leader_id = Some("n1".into());
        }
        assert!(
            !raft.is_leader_ready(),
            "a replaced local address must not use the single-node self-quorum shortcut"
        );

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn removed_configured_voter_rejects_append_entries_without_term_mutation() {
        let dir = temp_dir("raft-removed-voter-rejects-append");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 3;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.voted_for = Some("n1".into());
        }
        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n2", 7981),
            test_peer("n3", 7982),
            test_peer("n4", 7983),
        ]))
        .expect("apply membership removing local node");
        let initial_deadline = raft.runtime.lock().election_deadline;

        let response = raft.handle_append_entries(4, "n2".into(), 0, 0, Vec::new(), 0);

        assert!(matches!(
            response,
            RaftRpcResponse::AppendEntries {
                term: 3,
                success: false,
                ..
            }
        ));
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.current_term, 3);
            assert_eq!(runtime.role, RaftRole::Follower);
            assert_eq!(runtime.leader_id, None);
            assert_eq!(runtime.voted_for, None);
            assert_eq!(runtime.election_deadline, initial_deadline);
        }
        assert!(raft.log.read_entries().expect("entries").is_empty());
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.follower_append_sender_rejections_total, 1);
        assert_eq!(telemetry.local_removed_voter_guard_rejections_total, 1);
        assert_eq!(telemetry.append_entries_malformed_requests_total, 0);
        assert!(dir.join(LOCAL_VOTER_STATE_FILE).exists());

        let _ = fs::remove_dir_all(dir);
    }

