        let staged_learner = test_peer("n4", 7983);
        let transient_learner = test_peer("n5", 7984);
        commit_local_entry(
            &raft,
            2,
            RaftCommand::SetStagedLearners {
                learners: vec![staged_learner.clone()],
            },
        );
