    #[test]
    fn joint_membership_entry_requires_old_and_new_quorums_to_commit() {
        let dir = temp_dir("raft-joint-membership-requires-new-quorum");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let old_peers = vec![
            test_peer("n1", 7980),
            test_peer("n2", 7981),
            test_peer("n3", 7982),
        ];
        let new_peers = vec![
            test_peer("n1", 7980),
            test_peer("n4", 7983),
            test_peer("n5", 7984),
            test_peer("n6", 7985),
            test_peer("n7", 7986),
        ];
        let joint = RaftMembership::Joint {
            old_peers: old_peers.clone(),
            new_peers: new_peers.clone(),
        };
        raft.log
            .append(
                3,
                RaftCommand::SetMembership {
                    membership: joint.clone(),
                },
            )
            .expect("append joint membership entry");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 3;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.membership = RaftMembership::from_simple(old_peers.clone());
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: 2,
                    match_index: 1,
                },
            );
            runtime.leader_progress.insert(
                "n4".into(),
                RaftPeerProgress {
                    next_index: 2,
                    match_index: 1,
                },
            );
        }

        let committed = raft
            .commit_leader_index_in_term_with_membership(1, 3, true, Some(&joint))
            .expect("joint commit should check both quorums");

        assert!(
            !committed,
            "old quorum n1+n2 and partial new quorum n1+n4 must not commit joint config"
        );
        assert_eq!(raft.membership(), RaftMembership::from_simple(old_peers));
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").commit_index,
            0
        );
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.commit_index, 0);
            assert_eq!(runtime.last_applied, 0);
        }

        {
            raft.runtime.lock().leader_progress.insert(
                "n5".into(),
                RaftPeerProgress {
                    next_index: 2,
                    match_index: 1,
                },
            );
        }
        let committed = raft
            .commit_leader_index_in_term_with_membership(1, 3, true, Some(&joint))
            .expect("joint commit should succeed after new quorum");

        assert!(committed);
        assert_eq!(raft.membership(), joint);
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").commit_index,
            1
        );
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.commit_index, 1);
            assert_eq!(runtime.last_applied, 1);
        }

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn final_membership_entry_commits_under_current_joint_quorum() {
        let dir = temp_dir("raft-final-membership-uses-joint-quorum");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let old_peers = vec![
            test_peer("n1", 7980),
            test_peer("n2", 7981),
            test_peer("n3", 7982),
        ];
        let new_peers = vec![
            test_peer("n1", 7980),
            test_peer("n4", 7983),
            test_peer("n5", 7984),
        ];
        let joint = RaftMembership::Joint {
            old_peers: old_peers.clone(),
            new_peers: new_peers.clone(),
        };
        let final_membership = RaftMembership::from_simple(new_peers);
        let entry = raft
            .log
            .append(
                5,
                RaftCommand::SetMembership {
                    membership: final_membership.clone(),
                },
            )
            .expect("append final membership entry");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 5;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.membership = joint;
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: entry.index.saturating_add(1),
                    match_index: entry.index,
                },
            );
        }

        let old_only_committed = raft
            .commit_leader_index_in_term(entry.index, 5, true)
            .expect("old-only final commit attempt");
        assert!(
            !old_only_committed,
            "final simple config must still require the current joint quorum before apply"
        );
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.commit_index, 0);
            assert_eq!(runtime.last_applied, 0);
            assert!(runtime.membership.is_joint());
        }

        {
            let mut runtime = raft.runtime.lock();
            runtime.leader_progress.insert(
                "n4".into(),
                RaftPeerProgress {
                    next_index: entry.index.saturating_add(1),
                    match_index: entry.index,
                },
            );
        }
        let joint_committed = raft
            .commit_leader_index_in_term(entry.index, 5, true)
            .expect("joint final commit attempt");
        assert!(joint_committed);
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.commit_index, entry.index);
            assert_eq!(runtime.last_applied, entry.index);
            assert_eq!(runtime.membership, final_membership);
            assert!(!runtime.leader_progress.contains_key("n2"));
            assert!(runtime.leader_progress.contains_key("n4"));
            assert!(runtime.leader_progress.contains_key("n5"));
        }

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn leader_commit_advancements_are_counted_and_exported() {
        let dir = temp_dir("raft-leader-commit-telemetry");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");

        for _ in 0..3 {
            raft.log.append(2, RaftCommand::Noop).expect("append noop");
        }
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 2;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: 3,
                    match_index: 2,
                },
            );
        }

        assert!(raft
            .commit_leader_index_in_term(2, 2, false)
            .expect("leader commit should advance"));
        assert!(raft
            .commit_leader_index_in_term(2, 2, false)
            .expect("duplicate leader commit check should be idempotent"));

        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.leader_commit_advancements_total, 1);
        assert_eq!(telemetry.leader_commit_advanced_entries_total, 2);
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_leader_commit_advancements_total 1"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_leader_commit_advanced_entries_total 2")
        );

        let _ = fs::remove_dir_all(dir);
    }

