    #[tokio::test]
    async fn no_wait_composite_acquire_grants_atomically_or_fails_fast_without_waiter() {
        let dir = temp_dir("raft-no-wait-composite");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        become_single_node_leader(&raft, 3);

        // All members free -> atomic grant of the whole composite, one entry.
        let granted = raft
            .run_ephemeral(
                composite_lock_request("nw-holder", &["nw-x", "nw-y"]),
                "nw-holder",
                Duration::ZERO,
                true,
            )
            .await
            .expect("holder composite")
            .expect("holder composite response");
        assert!(matches!(
            granted,
            Response::CompositeLock { acquired: true, .. }
        ));
        assert_eq!(raft.broker.metrics().holders, 2);
        assert_eq!(raft.broker.metrics().waiters, 0);
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);

        // Overlapping no-wait composite fails fast on the contended member and
        // never enqueues a waiter or appends a DropClient cleanup entry.
        let denied = raft
            .run_ephemeral(
                composite_lock_request("nw-contended", &["nw-y", "nw-z"]),
                "nw-contended",
                Duration::ZERO,
                true,
            )
            .await
            .expect("contended composite")
            .expect("contended composite response");
        assert!(matches!(
            denied,
            Response::CompositeLock {
                acquired: false,
                ..
            }
        ));
        assert_eq!(raft.broker.metrics().holders, 2);
        assert_eq!(raft.broker.metrics().waiters, 0);

        let entries = raft.log.read_entries().expect("entries");
        assert_eq!(
            entries.len(),
            2,
            "contended no-wait composite must not append a DropClient cleanup entry"
        );
        assert!(matches!(
            &entries[1].command,
            RaftCommand::ClientRequestWithIdentity {
                request: Request::Lock {
                    keys: Some(_),
                    wait: Some(false),
                    ..
                },
                ..
            }
        ));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn public_raft_requests_admit_bounded_composite_and_reject_oversized() {
        let dir = temp_dir("raft-composite-public-bounded");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        become_single_node_leader(&raft, 3);

        // A 3-key composite (the cap) is admitted, replicated, and granted
        // atomically through the normal deterministic-grant path.
        let acquired = raft
            .run_ephemeral(
                composite_lock_request("raft-union-a", &["union-c", "union-a", "union-b"]),
                "raft-union-a",
                Duration::ZERO,
                true,
            )
            .await
            .expect("bounded composite acquire should be admitted")
            .expect("composite acquire response");
        let (lock_uuid, fencing_tokens) = match acquired {
            Response::CompositeLock {
                acquired: true,
                keys,
                lock_uuid: Some(lock_uuid),
                fencing_tokens: Some(tokens),
                ..
            } => {
                // Broker sorts + dedups member keys; the response reflects that.
                assert_eq!(keys, vec!["union-a", "union-b", "union-c"]);
                (lock_uuid, tokens)
            }
            other => panic!("expected granted composite lock, got {other:?}"),
        };
        assert!(lock_uuid.starts_with("raft-"), "deterministic lock uuid");
        assert_eq!(fencing_tokens.len(), 3, "one fencing token per member key");
        assert_eq!(raft.broker.metrics().holders, 3);
        assert_eq!(raft.broker.metrics().waiters, 0);
        // Exactly one replicated log entry for the whole composite acquire.
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);

        // The matching composite unlock is also admitted and releases all keys.
        let released = raft
            .run_ephemeral(
                composite_unlock_request(
                    "raft-union-unlock",
                    &["union-a", "union-b", "union-c"],
                    &lock_uuid,
                ),
                "raft-union-unlock",
                Duration::ZERO,
                false,
            )
            .await
            .expect("bounded composite unlock should be admitted")
            .expect("composite unlock response");
        assert!(matches!(released, Response::Unlock { unlocked: true, .. }));
        assert_eq!(raft.broker.metrics().holders, 0);

        // Admission is capped by distinct keys, matching the broker's
        // sorted/deduped union semantics, not the raw `keys` array length.
        let deduped = raft
            .run_ephemeral(
                composite_lock_request(
                    "raft-union-deduped",
                    &["dup-b", "dup-a", "dup-b", "dup-c", "dup-a"],
                ),
                "raft-union-deduped",
                Duration::ZERO,
                true,
            )
            .await
            .expect("duplicate keys within the distinct cap should be admitted")
            .expect("deduped composite acquire response");
        let deduped_lock_uuid = match deduped {
            Response::CompositeLock {
                acquired: true,
                keys,
                lock_uuid: Some(lock_uuid),
                fencing_tokens: Some(tokens),
                ..
            } => {
                assert_eq!(keys, vec!["dup-a", "dup-b", "dup-c"]);
                assert_eq!(tokens.len(), 3);
                lock_uuid
            }
            other => panic!("expected deduped composite lock, got {other:?}"),
        };
        let deduped_release = raft
            .run_ephemeral(
                composite_unlock_request(
                    "raft-union-deduped-unlock",
                    &["dup-c", "dup-a", "dup-a", "dup-b"],
                    &deduped_lock_uuid,
                ),
                "raft-union-deduped-unlock",
                Duration::ZERO,
                false,
            )
            .await
            .expect("duplicate-key composite unlock should be admitted")
            .expect("deduped composite unlock response");
        assert!(matches!(
            deduped_release,
            Response::Unlock { unlocked: true, .. }
        ));
        assert_eq!(raft.broker.metrics().holders, 0);

        // A composite above the distinct-key cap is rejected before any append.
        let entries_before = raft.log.read_entries().expect("entries").len();
        let oversized = raft
            .run_ephemeral(
                composite_lock_request("raft-union-big", &["a", "b", "c", "d"]),
                "raft-union-big",
                Duration::ZERO,
                true,
            )
            .await
            .expect_err("oversized composite acquire must be rejected");
        assert!(matches!(
            oversized,
            BrokerRaftError::UnsupportedClientRequest(message)
                if message.contains("at most 3 distinct keys")
        ));

        // An empty `keys` composite is rejected before any append.
        let empty = raft
            .run_ephemeral(
                composite_lock_request("raft-union-empty", &[]),
                "raft-union-empty",
                Duration::ZERO,
                true,
            )
            .await
            .expect_err("empty composite acquire must be rejected");
        assert!(matches!(
            empty,
            BrokerRaftError::UnsupportedClientRequest(message)
                if message.contains("at least one key")
        ));

        // Oversized composite unlock is likewise rejected before append.
        let oversized_unlock = raft
            .run_ephemeral(
                composite_unlock_request("raft-union-big-unlock", &["a", "b", "c", "d"], "lock-id"),
                "raft-union-big-unlock",
                Duration::ZERO,
                false,
            )
            .await
            .expect_err("oversized composite unlock must be rejected");
        assert!(matches!(
            oversized_unlock,
            BrokerRaftError::UnsupportedClientRequest(message)
                if message.contains("at most 3 distinct keys")
        ));

        // None of the rejected requests appended anything.
        assert_eq!(
            raft.log.read_entries().expect("entries").len(),
            entries_before
        );

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn duplicate_ephemeral_request_id_returns_cached_response_without_second_append() {
        let dir = temp_dir("raft-duplicate-request-id-cache");
        let mut cfg = test_raft_config(dir.clone());
        cfg.client_response_cache_max_entries = 8;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 3;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.membership = RaftMembership::from_simple(vec![test_peer("n1", 7980)]);
            runtime.leader_progress.clear();
        }
        raft.note_leader_quorum_observed();

        let request = single_lock_request("retry-request", "retry-key");
        let first = raft
            .run_ephemeral(request.clone(), "retry-request", Duration::ZERO, true)
            .await
            .expect("first request")
            .expect("first response");
        let second = raft
            .run_ephemeral(request, "retry-request", Duration::ZERO, true)
            .await
            .expect("cached request")
            .expect("cached response");

        assert_eq!(granted_lock_uuid(&first), granted_lock_uuid(&second));
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);

        let conflict = raft
            .run_ephemeral(
                single_lock_request("retry-request", "different-key"),
                "retry-request",
                Duration::ZERO,
                true,
            )
            .await
            .expect_err("same request id with different payload must conflict");
        assert!(matches!(
            conflict,
            BrokerRaftError::IdempotencyKeyConflict { .. }
        ));
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.client_proposals_total, 1);
        assert_eq!(telemetry.client_batches_total, 1);
        assert_eq!(telemetry.client_batch_entries_total, 1);
        assert_eq!(telemetry.client_batch_pipeline_batches_total, 1);
        assert_eq!(telemetry.client_cache_completed_hits_total, 1);
        assert_eq!(telemetry.client_cache_pending_hits_total, 0);
        assert_eq!(telemetry.client_cache_conflicts_total, 1);
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_proposals_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_batches_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_batch_entries_total 1"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_client_batch_pipeline_batches_total 1")
        );
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_cache_completed_hits_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_cache_conflicts_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_response_cache_entries 1"));

        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn invalid_snapshot_response_cache_restore_preserves_existing_cache() {
        let dir = temp_dir("raft-invalid-response-cache-restore");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        raft.restore_client_response_cache(vec![ClientResponseSnapshotEntry {
            request_id: "existing-request".into(),
            request_fingerprint: "existing-fingerprint".into(),
            response: None,
        }])
        .expect("restore valid cache entry");

        let err = raft
            .restore_client_response_cache(vec![
                ClientResponseSnapshotEntry {
                    request_id: "duplicate-request".into(),
                    request_fingerprint: "first-fingerprint".into(),
                    response: None,
                },
                ClientResponseSnapshotEntry {
                    request_id: "duplicate-request".into(),
                    request_fingerprint: "second-fingerprint".into(),
                    response: None,
                },
            ])
            .expect_err("duplicate snapshot cache entry should fail restore");

        assert!(matches!(
            err,
            BrokerRaftError::InvalidLog(message)
                if message.contains("duplicates request id `duplicate-request`")
        ));
        let cache = raft.client_response_cache.lock();
        assert_eq!(
            cache.order.iter().cloned().collect::<Vec<_>>(),
            vec!["existing-request".to_string()]
        );
        assert!(cache.entries.contains_key("existing-request"));
        assert!(!cache.entries.contains_key("duplicate-request"));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn duplicate_request_id_while_batch_pending_does_not_append_again() {
        let dir = temp_dir("raft-duplicate-request-id-pending-batch");
        let mut cfg = test_raft_config(dir.clone());
        cfg.client_response_cache_max_entries = 8;
        cfg.client_batch_max_entries = 2;
        cfg.client_batch_max_delay = Duration::from_secs(60);
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 3;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.membership = RaftMembership::from_simple(vec![test_peer("n1", 7980)]);
            runtime.leader_progress.clear();
        }
        raft.note_leader_quorum_observed();

        let request = single_lock_request("pending-request", "pending-key");
        let node = raft.clone();
        let first_request = request.clone();
        let first = tokio::spawn(async move {
            node.run_ephemeral(first_request, "pending-request", Duration::ZERO, true)
                .await
        });
        tokio::time::timeout(Duration::from_secs(3), raft.client_batch_waiting.notified())
            .await
            .expect("batch driver should wait for coalescing delay");

        let duplicate = raft
            .run_ephemeral(request, "pending-request", Duration::ZERO, true)
            .await
            .expect("duplicate pending request");
        assert!(
            duplicate.is_none(),
            "duplicate retry should observe the in-flight request instead of appending"
        );
        assert!(
            raft.log.read_entries().expect("entries").is_empty(),
            "nothing should be appended while the first request is still batched"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.client_cache_pending_hits_total, 1);
        assert_eq!(telemetry.client_proposals_total, 1);
        assert_eq!(telemetry.client_batches_total, 0);
        assert!(raft
            .raft_metrics_text()
            .contains("dd_rust_network_mutex_raft_client_cache_pending_hits_total 1"));

        raft.client_batch_notify.notify_one();
        let first_response = first
            .await
            .expect("first task")
            .expect("first request")
            .expect("first response");
        assert!(matches!(
            first_response,
            Response::Lock { acquired: true, .. }
        ));
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn pending_request_id_survives_response_cache_trim() {
        let dir = temp_dir("raft-pending-request-id-survives-cache-trim");
        let mut cfg = test_raft_config(dir.clone());
        cfg.client_response_cache_max_entries = 1;
        cfg.client_batch_max_entries = 4;
        cfg.client_batch_max_delay = Duration::from_secs(60);
        let raft = BrokerRaft::open(cfg).expect("open raft");
        become_single_node_leader(&raft, 3);

        let first_request = single_lock_request("trim-pending-a", "trim-pending-key-a");
        let first = {
            let node = raft.clone();
            tokio::spawn(async move {
                node.run_ephemeral(first_request, "trim-pending-a", Duration::ZERO, true)
                    .await
            })
        };
        tokio::time::timeout(Duration::from_secs(3), raft.client_batch_waiting.notified())
            .await
            .expect("batch driver should wait for first coalescing delay");

        let second_request = single_lock_request("trim-pending-b", "trim-pending-key-b");
        let second = {
            let node = raft.clone();
            tokio::spawn(async move {
                node.run_ephemeral(second_request, "trim-pending-b", Duration::ZERO, true)
                    .await
            })
        };
        tokio::time::timeout(Duration::from_secs(1), async {
            loop {
                if raft.client_request_batch.lock().pending.len() >= 2 {
                    break;
                }
                tokio::task::yield_now().await;
            }
        })
        .await
        .expect("second request should be queued before duplicate retry");

        {
            let cache = raft.client_response_cache.lock();
            assert_eq!(
                cache.entries.len(),
                2,
                "unapplied request-id reservations may temporarily exceed the completed-response cache limit"
            );
            assert!(cache
                .entries
                .get("trim-pending-a")
                .is_some_and(|cached| !cached.applied));
            assert!(cache
                .entries
                .get("trim-pending-b")
                .is_some_and(|cached| !cached.applied));
        }
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_response_cache_entries 2"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_client_response_cache_pending_entries 2")
        );
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_client_response_cache_completed_entries 0"));
        assert!(metrics.contains(
            "dd_rust_network_mutex_raft_client_response_cache_applied_without_response_entries 0"
        ));

        let duplicate = raft
            .run_ephemeral(
                single_lock_request("trim-pending-a", "trim-pending-key-a"),
                "trim-pending-a",
                Duration::ZERO,
                true,
            )
            .await
            .expect("duplicate pending request should not error");
        assert!(
            duplicate.is_none(),
            "duplicate retry should still observe the first request id as pending after cache trim"
        );
        assert_eq!(
            raft.client_request_batch.lock().pending.len(),
            2,
            "duplicate pending request must not enqueue a second log command"
        );
        assert!(
            raft.log.read_entries().expect("entries").is_empty(),
            "no request should append before the delayed batch is released"
        );

        raft.client_batch_notify.notify_one();
        let first_response = first
            .await
            .expect("first task")
            .expect("first request")
            .expect("first response");
        let second_response = second
            .await
            .expect("second task")
            .expect("second request")
            .expect("second response");
        assert!(matches!(
            first_response,
            Response::Lock { acquired: true, .. }
        ));
        assert!(matches!(
            second_response,
            Response::Lock { acquired: true, .. }
        ));
        assert_eq!(raft.log.read_entries().expect("entries").len(), 2);
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.client_cache_pending_hits_total, 1);
        assert_eq!(telemetry.client_proposals_total, 2);
        assert_eq!(telemetry.client_batches_total, 1);
        assert_eq!(telemetry.client_batch_entries_total, 2);
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_client_response_cache_entries 1"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_client_response_cache_pending_entries 0")
        );
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_client_response_cache_completed_entries 1"));
        assert!(metrics.contains(
            "dd_rust_network_mutex_raft_client_response_cache_applied_without_response_entries 0"
        ));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn request_id_reservation_is_released_when_queue_full_before_append() {
        let dir = temp_dir("raft-request-id-queue-full-release");
        let mut cfg = test_raft_config(dir.clone());
        cfg.client_response_cache_max_entries = 8;
        cfg.client_batch_max_pending = 1;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 3;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.membership = RaftMembership::from_simple(vec![test_peer("n1", 7980)]);
            runtime.leader_progress.clear();
        }
        raft.note_leader_quorum_observed();

        let (queued_client, _) = raft.register_client();
        let (result_tx, _result_rx) = oneshot::channel();
        {
            let mut state = raft.client_request_batch.lock();
            state.driver_active = true;
            state.pending.push_back(PendingClientRequest {
                client_id: queued_client,
                request: single_lock_request("held-queue-entry", "held-queue-key"),
                request_id: None,
                request_fingerprint: None,
                enqueued_at: Instant::now(),
                result_tx,
            });
        }

        let request = single_lock_request("retry-after-full", "retry-after-full-key");
        let err = raft
            .run_ephemeral(request.clone(), "retry-after-full", Duration::ZERO, true)
            .await
            .expect_err("queue-full request should fail before append");
        assert!(matches!(err, BrokerRaftError::ClientQueueFull { .. }));
        assert!(raft.log.read_entries().expect("entries").is_empty());

        {
            let mut state = raft.client_request_batch.lock();
            state.pending.clear();
            state.driver_active = false;
        }
        let retried = raft
            .run_ephemeral(request, "retry-after-full", Duration::ZERO, true)
            .await
            .expect("retry after queue space")
            .expect("retry response");
        assert!(matches!(retried, Response::Lock { acquired: true, .. }));
        assert_eq!(raft.log.read_entries().expect("entries").len(), 1);

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn cancelled_client_batch_entries_are_pruned_before_append() {
        let dir = temp_dir("raft-client-batch-cancelled-prune");
        let mut cfg = test_raft_config(dir.clone());
        cfg.client_response_cache_max_entries = 8;
        cfg.client_batch_max_entries = 8;
        cfg.client_pipeline_max_batches = 1;
        cfg.client_batch_max_delay = Duration::ZERO;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        become_single_node_leader(&raft, 3);

        let request_id = "cancelled-before-append";
        let request = single_lock_request(request_id, "cancelled-before-append-key");
        let request_fingerprint = request_fingerprint(&request).expect("request fingerprint");
        assert!(raft
            .reserve_client_request_id(request_id, &request_fingerprint)
            .expect("reserve idempotency key"));
        {
            let cache = raft.client_response_cache.lock();
            let cached = cache
                .entries
                .get(request_id)
                .expect("reserved request id should be cached");
            assert!(!cached.applied);
            assert!(cached.response.is_none());
        }

        let (client_id, _response_rx) = raft.register_client();
        let (result_tx, result_rx) = oneshot::channel();
        drop(result_rx);
        {
            let mut state = raft.client_request_batch.lock();
            state.driver_active = true;
            state.pending.push_back(PendingClientRequest {
                client_id,
                request,
                request_id: Some(request_id.to_string()),
                request_fingerprint: Some(request_fingerprint.clone()),
                enqueued_at: Instant::now() - Duration::from_millis(5),
                result_tx,
            });
        }

        tokio::time::timeout(Duration::from_secs(1), raft.drive_client_request_batches())
            .await
            .expect("batch driver should finish");

        assert!(raft.log.read_entries().expect("entries").is_empty());
        {
            let state = raft.client_request_batch.lock();
            assert!(state.pending.is_empty());
            assert!(!state.driver_active);
        }
        assert!(
            !raft
                .client_response_cache
                .lock()
                .entries
                .contains_key(request_id),
            "cancelled pre-append request id reservation should be released"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.client_batch_cancelled_requests_total, 1);
        assert_eq!(telemetry.client_batches_total, 0);
        assert_eq!(telemetry.client_batch_entries_total, 0);
        assert_eq!(telemetry.client_batch_commit_lock_waits_total, 0);
        assert!(raft
            .raft_metrics_text()
            .contains("dd_rust_network_mutex_raft_client_batch_cancelled_requests_total 1"));

        let _ = fs::remove_dir_all(dir);
    }

