    #[test]
    fn install_snapshot_chunk_frame_accounts_for_exact_frame_cap() {
        let payload = vec![b'x'; 4096];
        let checksum = sha256_hex(&payload);
        let meta = InstallSnapshotFrameMeta {
            auth_token: Some("peer-token-for-sizing"),
            term: 4,
            leader_id: "node-with-a-long-ish-id",
            leader_addr: "127.0.0.1:7980",
            last_included_index: 7,
            last_included_term: 3,
            payload_sha256: &checksum,
        };

        let unbounded = build_bounded_install_snapshot_rpc(&meta, &payload, 0, 4096, usize::MAX)
            .expect("unbounded snapshot frame");
        assert_eq!(unbounded.raw_len, 4096);
        assert!(!unbounded.frame_clamped);

        let mid_chunk =
            install_snapshot_chunk_frame(&meta, &payload, 64, 128).expect("mid snapshot frame");
        let mid_data = BASE64.encode(&payload[64..192]);
        let mid_view_bytes =
            serde_json::to_vec(&install_snapshot_frame_view(&meta, 64, false, &mid_data))
                .expect("serialize borrowed snapshot frame view");
        assert_eq!(mid_chunk.request_kind, RaftRpcRequestKind::InstallSnapshot);
        assert_eq!(mid_chunk.body, mid_view_bytes);
        assert_eq!(mid_chunk.frame_len, mid_view_bytes.len());
        assert!(
            matches!(
                serde_json::from_slice::<RaftRpc>(&mid_chunk.body).expect("parse snapshot frame body"),
                RaftRpc::InstallSnapshot { offset: 64, done: false, data, .. } if data == mid_data
            ),
            "prebuilt snapshot body should still decode as InstallSnapshot"
        );
        assert_eq!(
            install_snapshot_chunk_frame_len(&meta, &payload, 64, 128)
                .expect("borrowed snapshot frame len"),
            mid_view_bytes.len()
        );

        let final_offset = payload.len() - 37;
        let final_chunk = install_snapshot_chunk_frame(&meta, &payload, final_offset, 37)
            .expect("final snapshot frame");
        let final_data = BASE64.encode(&payload[final_offset..]);
        let final_view_bytes = serde_json::to_vec(&install_snapshot_frame_view(
            &meta,
            final_offset,
            true,
            &final_data,
        ))
        .expect("serialize borrowed final snapshot frame view");
        assert_eq!(
            final_chunk.request_kind,
            RaftRpcRequestKind::InstallSnapshot
        );
        assert_eq!(final_chunk.body, final_view_bytes);
        assert_eq!(final_chunk.frame_len, final_view_bytes.len());

        let no_auth_meta = InstallSnapshotFrameMeta {
            auth_token: None,
            ..meta
        };
        let no_auth_frame =
            install_snapshot_chunk_frame(&no_auth_meta, &payload, 0, 32).expect("no-auth frame");
        let no_auth_data = BASE64.encode(&payload[..32]);
        let no_auth_view_bytes = serde_json::to_vec(&install_snapshot_frame_view(
            &no_auth_meta,
            0,
            false,
            &no_auth_data,
        ))
        .expect("serialize borrowed no-auth snapshot frame view");
        assert_eq!(
            no_auth_frame.request_kind,
            RaftRpcRequestKind::InstallSnapshot
        );
        assert_eq!(no_auth_frame.body, no_auth_view_bytes);
        assert_eq!(no_auth_frame.frame_len, no_auth_view_bytes.len());

        let cap = 512;
        let bounded = build_bounded_install_snapshot_rpc(&meta, &payload, 0, 4096, cap)
            .expect("bounded snapshot frame");
        assert!(bounded.frame_clamped);
        assert!(bounded.raw_len > 0);
        assert!(bounded.raw_len < 4096);
        assert!(bounded.frame_len <= cap);
        let next_larger = install_snapshot_chunk_frame(&meta, &payload, 0, bounded.raw_len + 1)
            .expect("next larger snapshot frame");
        assert!(next_larger.frame_len > cap);

        let too_small = build_bounded_install_snapshot_rpc(&meta, &payload, 0, 4096, 1)
            .expect_err("single-byte snapshot frame cannot fit into tiny cap");
        assert!(
            too_small
                .to_string()
                .contains("single-byte InstallSnapshot RPC frame"),
            "unexpected error: {too_small}"
        );
    }

    #[tokio::test]
    async fn install_snapshot_to_peer_ignores_premature_success_until_final_chunk() {
        let dir = temp_dir("raft-send-install-snapshot-premature-success");
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind fake snapshot peer");
        let peer_addr = listener.local_addr().expect("fake snapshot peer addr");
        let mut cfg = test_raft_config_with_n2_addr(dir.clone(), peer_addr);
        cfg.install_snapshot_chunk_bytes = 64;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let mut payload = idle_snapshot_payload();
        payload["note"] = json!("x".repeat(512));
        let expected_bytes = serde_json::to_vec(&payload).expect("snapshot bytes");
        let expected_chunks = (expected_bytes.len() + 63) / 64;
        raft.log
            .write_snapshot(7, 3, payload)
            .expect("write source snapshot");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 4;
            runtime.role = RaftRole::Leader;
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: 1,
                    match_index: 0,
                },
            );
        }

        let server = tokio::spawn(async move {
            let (stream, _) = listener.accept().await.expect("accept snapshot peer");
            let mut reader = TokioBufReader::new(stream);
            let mut chunks = 0usize;
            let mut expected_offset = 0u64;
            loop {
                let line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                    .await
                    .expect("read install snapshot chunk");
                let rpc: RaftRpc =
                    serde_json::from_str(&line).expect("parse install snapshot chunk");
                let (term, last_included_index, offset, done, data) = match rpc {
                    RaftRpc::InstallSnapshot {
                        term,
                        last_included_index,
                        offset,
                        done,
                        data,
                        ..
                    } => (term, last_included_index, offset, done, data),
                    other => panic!("unexpected rpc: {other:?}"),
                };
                assert_eq!(last_included_index, 7);
                assert_eq!(offset, expected_offset);
                let chunk = decode_snapshot_chunk(&data).expect("decode chunk");
                expected_offset += chunk.len() as u64;
                chunks += 1;
                let response = RaftRpcResponse::InstallSnapshot {
                    term,
                    success: true,
                    last_included_index: 7,
                };
                let body = serde_json::to_vec(&response).expect("snapshot response");
                reader
                    .get_mut()
                    .write_all(&body)
                    .await
                    .expect("write snapshot response");
                reader
                    .get_mut()
                    .write_all(b"\n")
                    .await
                    .expect("write snapshot newline");
                reader
                    .get_mut()
                    .flush()
                    .await
                    .expect("flush snapshot response");
                if done {
                    break chunks;
                }
            }
        });

        let peer = RaftPeerConfig {
            id: "n2".into(),
            addr: peer_addr.to_string(),
        };
        let outcome = raft
            .install_snapshot_to_peer(peer, 4, Some(7))
            .await
            .expect("install snapshot to fake peer");
        assert!(outcome.target_reached);
        assert_eq!(server.await.expect("snapshot peer server"), expected_chunks);
        let progress = raft
            .runtime
            .lock()
            .leader_progress
            .get("n2")
            .copied()
            .expect("progress");
        assert_eq!(progress.match_index, 7);
        assert_eq!(progress.next_index, 8);
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(
            telemetry.install_snapshot_premature_success_responses_total,
            expected_chunks.saturating_sub(1) as u64
        );
        assert_eq!(telemetry.install_snapshot_successes_total, 1);
        assert!(raft.raft_metrics_text().contains(&format!(
            "dd_rust_network_mutex_raft_install_snapshot_premature_success_responses_total {}",
            expected_chunks.saturating_sub(1)
        )));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn install_snapshot_response_after_stepdown_does_not_update_progress() {
        let dir = temp_dir("raft-send-install-snapshot-after-stepdown");
        let listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind fake snapshot peer");
        let peer_addr = listener.local_addr().expect("fake snapshot peer addr");
        let mut cfg = test_raft_config_with_n2_addr(dir.clone(), peer_addr);
        cfg.install_snapshot_chunk_bytes = 64;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let mut payload = idle_snapshot_payload();
        payload["note"] = json!("x".repeat(512));
        raft.log
            .write_snapshot(7, 3, payload)
            .expect("write source snapshot");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 4;
            runtime.role = RaftRole::Leader;
            runtime.leader_id = Some("n1".into());
            runtime.leader_progress.insert(
                "n2".into(),
                RaftPeerProgress {
                    next_index: 1,
                    match_index: 0,
                },
            );
        }

        let (request_seen_tx, request_seen_rx) = oneshot::channel();
        let (reply_tx, reply_rx) = oneshot::channel();
        let server = tokio::spawn(async move {
            let (stream, _) = listener.accept().await.expect("accept snapshot peer");
            let mut reader = TokioBufReader::new(stream);
            let line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read first install snapshot chunk");
            let rpc: RaftRpc = serde_json::from_str(&line).expect("parse install snapshot chunk");
            let term = match rpc {
                RaftRpc::InstallSnapshot {
                    term,
                    last_included_index,
                    offset,
                    done,
                    ..
                } => {
                    assert_eq!(last_included_index, 7);
                    assert_eq!(offset, 0);
                    assert!(!done, "test requires a multi-chunk snapshot stream");
                    term
                }
                other => panic!("unexpected rpc: {other:?}"),
            };
            request_seen_tx.send(()).expect("signal request seen");
            reply_rx.await.expect("wait for stepdown");
            let response = RaftRpcResponse::InstallSnapshot {
                term,
                success: true,
                last_included_index: 7,
            };
            let body = serde_json::to_vec(&response).expect("snapshot response");
            reader
                .get_mut()
                .write_all(&body)
                .await
                .expect("write snapshot response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write snapshot newline");
            reader
                .get_mut()
                .flush()
                .await
                .expect("flush snapshot response");

            let next = tokio::time::timeout(
                Duration::from_millis(100),
                read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes()),
            )
            .await;
            assert!(
                !matches!(next, Ok(Ok(_))),
                "stepped-down leader must not send a second InstallSnapshot chunk: {next:?}"
            );
        });

        let peer = RaftPeerConfig {
            id: "n2".into(),
            addr: peer_addr.to_string(),
        };
        let node = raft.clone();
        let install =
            tokio::spawn(async move { node.install_snapshot_to_peer(peer, 4, Some(7)).await });
        request_seen_rx
            .await
            .expect("snapshot request should be sent");
        raft.step_down(5, None);
        reply_tx.send(()).expect("release fake peer response");
        let outcome = install
            .await
            .expect("snapshot task")
            .expect("snapshot result");

        assert!(!outcome.contacted);
        assert!(!outcome.target_reached);
        server.await.expect("fake snapshot peer server");
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.current_term, 5);
            assert_eq!(runtime.role, RaftRole::Follower);
            let progress = runtime
                .leader_progress
                .get("n2")
                .copied()
                .expect("progress");
            assert_eq!(progress.match_index, 0);
            assert_eq!(progress.next_index, 1);
        }

        let _ = fs::remove_dir_all(dir);
    }

