        store
            .write_hard_state(&committed)
            .expect("write committed hard state");

        let newer_term_stale_commit = RaftHardState {
            current_term: 8,
            voted_for: Some("n3".into()),
            commit_index: 0,
        };
        store
            .write_hard_state(&newer_term_stale_commit)
