    #[tokio::test]
    async fn pre_vote_failure_suppresses_election_without_term_bump() {
        // Pre-vote is the guard against a partitioned/standalone node forcing a
        // disruptive election and incrementing the cluster term for nothing.
        // With a 3-node membership whose two peers are unreachable, the node can
        // only pre-vote for itself (1 of the required 2), so run_pre_vote fails
        // and start_election bails BEFORE bumping the term, voting for itself,
        // or appending a leader no-op.
        let dir = temp_dir("raft-pre-vote-suppresses-election");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let initial_state = {
            let mut runtime = raft.runtime.lock();
            // Full 3-voter membership; peers n2/n3 are not listening anywhere.
            runtime.membership = RaftMembership::from_simple(vec![
                test_peer("n1", 7980),
                test_peer("n2", 7981),
                test_peer("n3", 7982),
            ]);
            runtime.current_term = 5;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
            runtime.hard_state()
        };
        // Persist term 5 so the assertion below proves pre-vote failure does not
        // advance the *durable* term, not merely the in-memory one.
        raft.log
            .write_hard_state(&initial_state)
            .expect("persist initial term 5");

        raft.start_election()
            .await
            .expect("election attempt should not error when pre-vote fails");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(
                runtime.current_term, 5,
                "failed pre-vote must NOT advance the term"
            );
            assert_eq!(
                runtime.role,
                RaftRole::Follower,
                "node must stay a follower"
            );
            assert_eq!(
                runtime.voted_for, None,
                "failed pre-vote must not record a self-vote"
            );
        }
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").current_term,
            5,
            "no higher term should be persisted"
        );
        assert!(
            raft.log.read_entries().expect("entries").is_empty(),
            "a suppressed election must not append a leader no-op"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.pre_vote_rounds_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 0);
        assert_eq!(telemetry.pre_vote_quorum_failures_total, 1);
        assert_eq!(
            telemetry.election_terms_started_total, 0,
            "no real election term should be started when pre-vote fails"
        );

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn stale_lower_term_pre_vote_response_does_not_count_toward_quorum() {
        let dir = temp_dir("raft-pre-vote-stale-response-no-quorum");
        let listener_n2 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind stale pre-vote peer");
        let addr_n2 = listener_n2.local_addr().expect("stale peer addr");
        let listener_n3 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind closed peer");
        let addr_n3 = listener_n3.local_addr().expect("closed peer addr");
        drop(listener_n3);

        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(100);
        cfg.election_timeout_max = Duration::from_millis(200);
        cfg.peers = vec![
            test_peer("n1", 7980),
            RaftPeerConfig {
                id: "n2".into(),
                addr: addr_n2.to_string(),
            },
            RaftPeerConfig {
                id: "n3".into(),
                addr: addr_n3.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 5;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
        }
        raft.log
            .write_hard_state(&RaftHardState {
                current_term: 5,
                voted_for: None,
                commit_index: 0,
            })
            .expect("persist initial term");

        let stale_peer = tokio::spawn(async move {
            let (stream, _) = listener_n2.accept().await.expect("accept stale pre-vote");
            let mut reader = TokioBufReader::new(stream);
            let line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read stale pre-vote request");
            match serde_json::from_str(&line).expect("parse stale pre-vote request") {
                RaftRpc::PreVote { term, .. } => assert_eq!(term, 6),
                other => panic!("unexpected stale pre-vote rpc: {other:?}"),
            }
            let response = serde_json::to_vec(&RaftRpcResponse::PreVote {
                term: 4,
                vote_granted: true,
            })
            .expect("serialize stale pre-vote response");
            reader
                .get_mut()
                .write_all(&response)
                .await
                .expect("write stale pre-vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write stale pre-vote newline");
            reader
                .get_mut()
                .flush()
                .await
                .expect("flush stale pre-vote");
        });

        tokio::time::timeout(Duration::from_secs(1), raft.start_election())
            .await
            .expect("stale pre-vote round should finish")
            .expect("start election");
        stale_peer.await.expect("stale peer server");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.current_term, 5);
            assert_eq!(runtime.role, RaftRole::Follower);
            assert_eq!(runtime.voted_for, None);
            assert_eq!(runtime.leader_id, None);
        }
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").current_term,
            5
        );
        assert!(raft.log.read_entries().expect("entries").is_empty());
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.pre_vote_rounds_total, 1);
        assert_eq!(telemetry.pre_vote_stale_term_responses_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 0);
        assert_eq!(telemetry.pre_vote_quorum_failures_total, 1);
        assert_eq!(telemetry.election_terms_started_total, 0);
        assert!(raft
            .raft_metrics_text()
            .contains("dd_rust_network_mutex_raft_pre_vote_stale_term_responses_total 1"));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn elected_leader_appends_and_commits_current_term_noop() {
        let dir = temp_dir("raft-election-noop");
        let cfg = test_raft_config(dir.clone());
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.membership = RaftMembership::from_simple(vec![test_peer("n1", 7980)]);
            runtime.current_term = 0;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
        }

        raft.start_election().await.expect("single-node election");

        let entries = raft.log.read_entries().expect("read entries");
        assert_eq!(entries.len(), 1);
        assert_eq!(entries[0].term, 1);
        assert!(matches!(entries[0].command, RaftCommand::Noop));
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.role, RaftRole::Leader);
            assert_eq!(runtime.leader_id.as_deref(), Some("n1"));
            assert_eq!(runtime.current_term, 1);
            assert_eq!(runtime.voted_for.as_deref(), Some("n1"));
            assert_eq!(runtime.commit_index, entries[0].index);
            assert_eq!(runtime.last_applied, entries[0].index);
        }

        let hard_state = raft.log.read_hard_state().expect("read hard state");
        assert_eq!(hard_state.current_term, 1);
        assert_eq!(hard_state.voted_for.as_deref(), Some("n1"));
        assert_eq!(
            hard_state.commit_index, entries[0].index,
            "leader no-op commit persists commitIndex before applying"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.pre_vote_rounds_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_failures_total, 0);
        assert_eq!(telemetry.election_terms_started_total, 1);
        assert_eq!(telemetry.election_terms_won_total, 1);
        assert_eq!(telemetry.election_terms_lost_total, 0);
        assert_eq!(telemetry.election_deadline_resets_total, 2);
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_pre_vote_rounds_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_election_terms_won_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_election_terms_lost_total 0"));

        let _ = fs::remove_dir_all(dir);
    }

