    #[tokio::test]
    async fn election_does_not_wait_for_slow_peer_after_quorum() {
        let dir = temp_dir("raft-election-fast-quorum");
        let listener_n2 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind fast voter");
        let addr_n2 = listener_n2.local_addr().expect("fast voter addr");
        let listener_n3 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind slow voter");
        let addr_n3 = listener_n3.local_addr().expect("slow voter addr");

        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(700);
        cfg.election_timeout_max = Duration::from_millis(1_400);
        cfg.peers = vec![
            test_peer("n1", 7980),
            RaftPeerConfig {
                id: "n2".into(),
                addr: addr_n2.to_string(),
            },
            RaftPeerConfig {
                id: "n3".into(),
                addr: addr_n3.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let fast_server = tokio::spawn(async move {
            let (stream, _) = listener_n2.accept().await.expect("accept fast voter");
            let mut reader = TokioBufReader::new(stream);
            let pre_vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read pre-vote request");
            let pre_vote_term =
                match serde_json::from_str(&pre_vote_line).expect("parse pre-vote request") {
                    RaftRpc::PreVote { term, .. } => term,
                    other => panic!("unexpected pre-vote rpc: {other:?}"),
                };
            let pre_vote_response = serde_json::to_vec(&RaftRpcResponse::PreVote {
                term: pre_vote_term.saturating_sub(1),
                vote_granted: true,
            })
            .expect("serialize pre-vote response");
            reader
                .get_mut()
                .write_all(&pre_vote_response)
                .await
                .expect("write pre-vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write pre-vote newline");
            reader.get_mut().flush().await.expect("flush pre-vote");

            let vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read vote request");
            let vote_term = match serde_json::from_str(&vote_line).expect("parse vote request") {
                RaftRpc::RequestVote { term, .. } => term,
                other => panic!("unexpected vote rpc: {other:?}"),
            };
            let vote_response = serde_json::to_vec(&RaftRpcResponse::RequestVote {
                term: vote_term,
                vote_granted: true,
            })
            .expect("serialize vote response");
            reader
                .get_mut()
                .write_all(&vote_response)
                .await
                .expect("write vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write vote newline");
            reader.get_mut().flush().await.expect("flush vote");

            let append_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read leader noop append");
            let (append_term, match_index) =
                match serde_json::from_str(&append_line).expect("parse append request") {
                    RaftRpc::AppendEntries { term, entries, .. } => {
                        assert_eq!(
                            entries.iter().map(|entry| entry.index).collect::<Vec<_>>(),
                            vec![1]
                        );
                        (term, 1)
                    }
                    other => panic!("unexpected append rpc: {other:?}"),
                };
            let append_response = serde_json::to_vec(&RaftRpcResponse::AppendEntries {
                term: append_term,
                success: true,
                match_index,
                conflict_index: None,
                conflict_term: None,
            })
            .expect("serialize append response");
            reader
                .get_mut()
                .write_all(&append_response)
                .await
                .expect("write append response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write append newline");
            reader.get_mut().flush().await.expect("flush append");
        });
        let slow_server = tokio::spawn(async move {
            let (_stream, _) = listener_n3.accept().await.expect("accept slow voter");
            tokio::time::sleep(Duration::from_secs(5)).await;
        });

        let start = Instant::now();
        raft.start_election().await.expect("start fast election");
        let elapsed = start.elapsed();

        assert!(
            elapsed < Duration::from_millis(500),
            "election should not wait for slow peer timeout; elapsed={elapsed:?}"
        );
        fast_server.await.expect("fast voter server");
        slow_server.abort();
        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.role, RaftRole::Leader);
            assert_eq!(runtime.leader_id.as_deref(), Some("n1"));
            assert_eq!(runtime.commit_index, 1);
            assert_eq!(runtime.last_applied, 1);
        }

        let _ = fs::remove_dir_all(dir);
    }

    fn spawn_fake_election_voter(
        listener: TcpListener,
        pre_vote_response_term: impl Fn(u64) -> u64 + Send + 'static,
        pre_vote_granted: bool,
        request_vote_grant: Option<bool>,
    ) -> JoinHandle<()> {
        // Minimal fake Raft voter: accept one connection, answer a single
        // PreVote (response term derived from the observed pre-vote term so a
        // peer can claim a higher term), and optionally one RequestVote.
        tokio::spawn(async move {
            let (stream, _) = listener.accept().await.expect("accept fake voter");
            let mut reader = TokioBufReader::new(stream);

            let pre_vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read pre-vote request");
            let pre_vote_term =
                match serde_json::from_str(&pre_vote_line).expect("parse pre-vote request") {
                    RaftRpc::PreVote { term, .. } => term,
                    other => panic!("unexpected pre-vote rpc: {other:?}"),
                };
            let pre_vote_response = serde_json::to_vec(&RaftRpcResponse::PreVote {
                term: pre_vote_response_term(pre_vote_term),
                vote_granted: pre_vote_granted,
            })
            .expect("serialize pre-vote response");
            reader
                .get_mut()
                .write_all(&pre_vote_response)
                .await
                .expect("write pre-vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write pre-vote newline");
            reader.get_mut().flush().await.expect("flush pre-vote");

            if let Some(granted) = request_vote_grant {
                // Best-effort: if the candidate already met pre-vote quorum from
                // another peer, this peer's pre-vote task may have been aborted,
                // leaving the pooled connection half-read so the follow-up vote
                // request never lands here cleanly. That is fine — not answering
                // is equivalent to not granting, which is the outcome we want.
                let served = async {
                    let vote_line =
                        read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes()).await?;
                    let vote_term = match serde_json::from_str(&vote_line)
                        .map_err(|err| std::io::Error::new(std::io::ErrorKind::InvalidData, err))?
                    {
                        RaftRpc::RequestVote { term, .. } => term,
                        other => panic!("unexpected vote rpc: {other:?}"),
                    };
                    let vote_response = serde_json::to_vec(&RaftRpcResponse::RequestVote {
                        term: vote_term,
                        vote_granted: granted,
                    })
                    .map_err(|err| std::io::Error::new(std::io::ErrorKind::InvalidData, err))?;
                    reader.get_mut().write_all(&vote_response).await?;
                    reader.get_mut().write_all(b"\n").await?;
                    reader.get_mut().flush().await?;
                    Ok::<(), std::io::Error>(())
                }
                .await;
                let _ = served;
            }
        })
    }

    #[tokio::test]
    async fn candidate_without_majority_votes_stays_candidate_and_does_not_lead() {
        // Both peers grant the PRE-vote (so a real election starts and the term
        // bumps), then DENY the real RequestVote. The candidate ends with only
        // its own vote (1 of 3) — a minority — so it must NOT become leader and
        // must NOT append a leader no-op; it stays a candidate.
        let dir = temp_dir("raft-candidate-loses-minority");
        let listener_n2 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind voter n2");
        let addr_n2 = listener_n2.local_addr().expect("voter n2 addr");
        let listener_n3 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind voter n3");
        let addr_n3 = listener_n3.local_addr().expect("voter n3 addr");

        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(300);
        cfg.election_timeout_max = Duration::from_millis(600);
        cfg.peers = vec![
            test_peer("n1", 7980),
            RaftPeerConfig {
                id: "n2".into(),
                addr: addr_n2.to_string(),
            },
            RaftPeerConfig {
                id: "n3".into(),
                addr: addr_n3.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 0;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
        }

        let server_n2 = spawn_fake_election_voter(
            listener_n2,
            |term| term.saturating_sub(1),
            true,
            Some(false),
        );
        let server_n3 = spawn_fake_election_voter(
            listener_n3,
            |term| term.saturating_sub(1),
            true,
            Some(false),
        );

        raft.start_election()
            .await
            .expect("election attempt should complete without error");
        server_n2.await.expect("voter n2 server");
        server_n3.await.expect("voter n3 server");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(
                runtime.role,
                RaftRole::Candidate,
                "a candidate that fails to win a majority stays a candidate"
            );
            assert_eq!(runtime.leader_id, None, "no leader was elected");
            assert_eq!(runtime.current_term, 1, "the real election bumped the term");
            assert_eq!(runtime.voted_for.as_deref(), Some("n1"));
        }
        assert!(
            raft.log.read_entries().expect("entries").is_empty(),
            "a lost election must not append a leader no-op"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 1);
        assert_eq!(telemetry.election_terms_started_total, 1);
        assert_eq!(
            telemetry.election_terms_won_total, 0,
            "minority votes must not win the election"
        );
        assert_eq!(telemetry.election_terms_lost_total, 1);

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn pre_vote_steps_down_when_peer_reports_higher_term() {
        // If a peer answers the pre-vote with a HIGHER term, the candidate must
        // not start a disruptive election; it adopts the higher term and steps
        // down to follower. This is the term-discovery branch of pre-vote.
        let dir = temp_dir("raft-pre-vote-higher-term-stepdown");
        let listener_n2 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind voter n2");
        let addr_n2 = listener_n2.local_addr().expect("voter n2 addr");
        let listener_n3 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind closed voter n3");
        let addr_n3 = listener_n3.local_addr().expect("voter n3 addr");
        drop(listener_n3); // n3 unreachable; n2's higher term drives the result

        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(300);
        cfg.election_timeout_max = Duration::from_millis(600);
        cfg.peers = vec![
            test_peer("n1", 7980),
            RaftPeerConfig {
                id: "n2".into(),
                addr: addr_n2.to_string(),
            },
            RaftPeerConfig {
                id: "n3".into(),
                addr: addr_n3.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let initial_state = {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 5;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
            runtime.hard_state()
        };
        raft.log
            .write_hard_state(&initial_state)
            .expect("persist initial term 5");

        let server_n2 = spawn_fake_election_voter(listener_n2, |_| 9, false, None);

        raft.start_election()
            .await
            .expect("election attempt should complete without error");
        server_n2.await.expect("voter n2 server");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(
                runtime.current_term, 9,
                "candidate adopts the peer's higher term from pre-vote"
            );
            assert_eq!(
                runtime.role,
                RaftRole::Follower,
                "candidate steps down to follower on a higher term"
            );
            assert_eq!(runtime.voted_for, None, "step-down clears any vote");
        }
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").current_term,
            9,
            "the higher term is persisted durably"
        );
        assert!(
            raft.log.read_entries().expect("entries").is_empty(),
            "no election no-op should be appended"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.pre_vote_quorum_failures_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 0);
        assert_eq!(
            telemetry.election_terms_started_total, 0,
            "no real election term when pre-vote discovers a higher term"
        );

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn pre_vote_higher_term_from_replaced_peer_address_does_not_step_down() {
        let dir = temp_dir("raft-pre-vote-higher-term-replaced-peer-address");
        let old_listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind old voter");
        let old_addr = old_listener.local_addr().expect("old voter addr");
        let replacement_listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind replacement voter");
        let replacement_addr = replacement_listener
            .local_addr()
            .expect("replacement voter addr");
        let slow_listener = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind slow voter");
        let slow_addr = slow_listener.local_addr().expect("slow voter addr");

        let old_peer = RaftPeerConfig {
            id: "n2".into(),
            addr: old_addr.to_string(),
        };
        let replacement_peer = RaftPeerConfig {
            id: "n2".into(),
            addr: replacement_addr.to_string(),
        };
        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(100);
        cfg.election_timeout_max = Duration::from_millis(200);
        cfg.peers = vec![
            test_peer("n1", 7980),
            old_peer.clone(),
            RaftPeerConfig {
                id: "n3".into(),
                addr: slow_addr.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let initial_state = {
            let mut runtime = raft.runtime.lock();
            runtime.current_term = 5;
            runtime.voted_for = None;
            runtime.role = RaftRole::Follower;
            runtime.leader_id = None;
            runtime.hard_state()
        };
        raft.log
            .write_hard_state(&initial_state)
            .expect("persist initial term 5");

        let (pre_vote_seen_tx, pre_vote_seen_rx) = oneshot::channel();
        let (release_response_tx, release_response_rx) = oneshot::channel();
        let slow_voter = tokio::spawn(async move {
            let (_stream, _) = slow_listener.accept().await.expect("accept slow voter");
            tokio::time::sleep(Duration::from_secs(5)).await;
        });
        let old_voter = tokio::spawn(async move {
            let (stream, _) = old_listener.accept().await.expect("accept old voter");
            let mut reader = TokioBufReader::new(stream);
            let pre_vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read pre-vote request");
            let pre_vote_term =
                match serde_json::from_str(&pre_vote_line).expect("parse pre-vote request") {
                    RaftRpc::PreVote { term, .. } => term,
                    other => panic!("unexpected pre-vote rpc: {other:?}"),
                };
            assert_eq!(pre_vote_term, 6);
            pre_vote_seen_tx.send(()).expect("signal pre-vote");
            release_response_rx.await.expect("wait for address swap");
            let response = serde_json::to_vec(&RaftRpcResponse::PreVote {
                term: 9,
                vote_granted: true,
            })
            .expect("serialize pre-vote response");
            reader
                .get_mut()
                .write_all(&response)
                .await
                .expect("write pre-vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write pre-vote newline");
            reader.get_mut().flush().await.expect("flush pre-vote");
        });

        let node = raft.clone();
        let election = tokio::spawn(async move { node.start_election().await });
        pre_vote_seen_rx.await.expect("wait for pre-vote request");
        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n1", 7980),
            replacement_peer.clone(),
            RaftPeerConfig {
                id: "n3".into(),
                addr: slow_addr.to_string(),
            },
        ]))
        .expect("replace voter address during pre-vote");
        release_response_tx
            .send(())
            .expect("release old voter response");

        tokio::time::timeout(Duration::from_secs(2), election)
            .await
            .expect("election should finish")
            .expect("election task")
            .expect("election should not error");
        old_voter.await.expect("old voter task");
        slow_voter.abort();
        drop(replacement_listener);

        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.current_term, 5);
            assert_eq!(runtime.role, RaftRole::Follower);
            assert_eq!(runtime.voted_for, None);
            assert!(runtime.accepts_active_peer(&replacement_peer));
            assert!(!runtime.accepts_active_peer(&old_peer));
        }
        assert_eq!(
            raft.log.read_hard_state().expect("hard state").current_term,
            5
        );
        assert!(raft.log.read_entries().expect("entries").is_empty());
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.election_removed_peer_responses_total, 1);
        assert_eq!(telemetry.pre_vote_quorum_successes_total, 0);
        assert_eq!(telemetry.pre_vote_quorum_failures_total, 1);
        assert_eq!(telemetry.election_terms_started_total, 0);
        assert!(raft
            .raft_metrics_text()
            .contains("dd_rust_network_mutex_raft_election_removed_peer_responses_total 1"));

        let _ = fs::remove_dir_all(dir);
    }

    #[tokio::test]
    async fn election_aborts_if_membership_changes_during_vote_round() {
        let dir = temp_dir("raft-election-membership-change-mid-round");
        let listener_n2 = TcpListener::bind("127.0.0.1:0").await.expect("bind voter");
        let addr_n2 = listener_n2.local_addr().expect("voter addr");
        let listener_n3 = TcpListener::bind("127.0.0.1:0")
            .await
            .expect("bind closed voter");
        let addr_n3 = listener_n3.local_addr().expect("closed voter addr");
        drop(listener_n3);

        let peer_n2 = RaftPeerConfig {
            id: "n2".into(),
            addr: addr_n2.to_string(),
        };
        let mut cfg = test_raft_config(dir.clone());
        cfg.heartbeat_interval = Duration::from_millis(10);
        cfg.election_timeout_min = Duration::from_millis(50);
        cfg.election_timeout_max = Duration::from_millis(100);
        cfg.peers = vec![
            test_peer("n1", 7980),
            peer_n2.clone(),
            RaftPeerConfig {
                id: "n3".into(),
                addr: addr_n3.to_string(),
            },
        ];
        let raft = BrokerRaft::open(cfg).expect("open raft");
        let (vote_seen_tx, vote_seen_rx) = oneshot::channel();
        let (release_vote_tx, release_vote_rx) = oneshot::channel();
        let voter = tokio::spawn(async move {
            let (stream, _) = listener_n2.accept().await.expect("accept voter");
            let mut reader = TokioBufReader::new(stream);
            let pre_vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read pre-vote request");
            let pre_vote_term =
                match serde_json::from_str(&pre_vote_line).expect("parse pre-vote request") {
                    RaftRpc::PreVote { term, .. } => term,
                    other => panic!("unexpected pre-vote rpc: {other:?}"),
                };
            let pre_vote_response = serde_json::to_vec(&RaftRpcResponse::PreVote {
                term: pre_vote_term.saturating_sub(1),
                vote_granted: true,
            })
            .expect("serialize pre-vote response");
            reader
                .get_mut()
                .write_all(&pre_vote_response)
                .await
                .expect("write pre-vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write pre-vote newline");
            reader.get_mut().flush().await.expect("flush pre-vote");

            let vote_line = read_raft_frame_bounded(&mut reader, raft_rpc_max_frame_bytes())
                .await
                .expect("read vote request");
            let vote_term = match serde_json::from_str(&vote_line).expect("parse vote request") {
                RaftRpc::RequestVote { term, .. } => term,
                other => panic!("unexpected vote rpc: {other:?}"),
            };
            vote_seen_tx.send(()).expect("signal vote request seen");
            release_vote_rx.await.expect("wait to release vote");
            let vote_response = serde_json::to_vec(&RaftRpcResponse::RequestVote {
                term: vote_term,
                vote_granted: true,
            })
            .expect("serialize vote response");
            reader
                .get_mut()
                .write_all(&vote_response)
                .await
                .expect("write vote response");
            reader
                .get_mut()
                .write_all(b"\n")
                .await
                .expect("write vote newline");
            reader.get_mut().flush().await.expect("flush vote");
        });

        let node = raft.clone();
        let election = tokio::spawn(async move { node.start_election().await });
        vote_seen_rx.await.expect("wait for candidate vote request");
        raft.apply_membership(RaftMembership::from_simple(vec![
            test_peer("n1", 7980),
            peer_n2,
            test_peer("n4", 7984),
        ]))
        .expect("apply changed membership while vote is in flight");
        release_vote_tx.send(()).expect("release vote response");

        tokio::time::timeout(Duration::from_secs(2), election)
            .await
            .expect("election should finish")
            .expect("election task should not panic")
            .expect("election should not error");
        voter.await.expect("voter task");

        {
            let runtime = raft.runtime.lock();
            assert_eq!(runtime.current_term, 1);
            assert_eq!(runtime.role, RaftRole::Candidate);
            assert_eq!(runtime.leader_id, None);
            assert_eq!(runtime.voted_for.as_deref(), Some("n1"));
            assert!(runtime.membership.contains_id("n4"));
            assert!(!runtime.membership.contains_id("n3"));
            assert!(runtime.leader_progress.is_empty());
            assert_eq!(runtime.commit_index, 0);
            assert_eq!(runtime.last_applied, 0);
        }
        assert!(
            raft.log
                .read_entries()
                .expect("read log entries")
                .is_empty(),
            "membership churn during election must prevent the leader no-op append"
        );
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.election_terms_won_total, 0);
        assert_eq!(telemetry.election_terms_lost_total, 1);

        let _ = fs::remove_dir_all(dir);
    }

