    #[test]
    fn deterministic_grant_plan_replays_same_fencing_token_on_independent_nodes() {
        let request = single_lock_request("deterministic-raft-lock", "deterministic-key");
        let command = command_with_deterministic_grant(
            RaftCommand::ClientRequest {
                client_id: 42,
                request: request.clone(),
                grant: None,
            },
            11,
        );
        let expected_token = deterministic_fencing_seed(11);
        let expected_lock_uuid = deterministic_lock_uuid(11);

        for suffix in ["a", "b"] {
            let dir = temp_dir(&format!("raft-deterministic-fencing-{suffix}"));
            let cfg = test_raft_config(dir.clone());
            let raft = BrokerRaft::open(cfg).expect("open raft");
            let entry = raft.log.append(4, command.clone()).expect("append command");
            {
                let mut runtime = raft.runtime.lock();
                runtime.commit_index = entry.index;
            }
            raft.apply_committed().expect("apply deterministic command");
            let top = raft.broker.top_keys(1);
            assert_eq!(top.len(), 1);
            assert_eq!(top[0].key, "deterministic-key");
            assert_eq!(top[0].fencing_counter, expected_token);
            assert_eq!(
                raft.broker
                    .top_keys(1)
                    .first()
                    .map(|snapshot| snapshot.exclusive_holders),
                Some(1)
            );
            assert!(matches!(
                &command,
                RaftCommand::ClientRequest {
                    grant: Some(RaftGrantPlan {
                        lock_uuid: Some(lock_uuid),
                        fencing_seed: Some(seed),
                    }),
                    ..
                } if lock_uuid == &expected_lock_uuid && *seed == expected_token
            ));
            let _ = fs::remove_dir_all(dir);
        }
    }

    #[test]
    fn deterministic_composite_grant_replays_same_uuid_and_per_key_tokens_on_independent_nodes() {
        // A composite is presented with keys out of order; the inner broker
        // sorts + dedups to [comp-a, comp-b, comp-c]. Each member key's
        // fencing token is seed + its position in that sorted order, and the
        // shared composite lock uuid is the deterministic uuid for the entry
        // index. Two independent nodes replaying the same committed entry must
        // mint identical uuids and identical per-key tokens.
        let request =
            composite_lock_request("deterministic-composite", &["comp-c", "comp-a", "comp-b"]);
        let command = command_with_deterministic_grant(
            RaftCommand::ClientRequest {
                client_id: 42,
                request,
                grant: None,
            },
            11,
        );
        let seed = deterministic_fencing_seed(11);
        let expected_lock_uuid = deterministic_lock_uuid(11);
        let expected_tokens: BTreeMap<String, u64> = [
            ("comp-a".to_string(), seed),
            ("comp-b".to_string(), seed + 1),
            ("comp-c".to_string(), seed + 2),
        ]
        .into_iter()
        .collect();
        // Three distinct member tokens fit strictly below the next index's
        // seed, proving the reservation width is sufficient for the cap.
        assert!(seed + 2 < deterministic_fencing_seed(12));

        for suffix in ["a", "b"] {
            let dir = temp_dir(&format!("raft-deterministic-composite-{suffix}"));
            let cfg = test_raft_config(dir.clone());
            let raft = BrokerRaft::open(cfg).expect("open raft");
            let entry = raft.log.append(4, command.clone()).expect("append command");
            {
                let mut runtime = raft.runtime.lock();
                runtime.commit_index = entry.index;
            }
            raft.apply_committed()
                .expect("apply deterministic composite");

            let tokens_by_key: BTreeMap<String, u64> = raft
                .broker
                .top_keys(16)
                .into_iter()
                .map(|snapshot| (snapshot.key, snapshot.fencing_counter))
                .collect();
            assert_eq!(tokens_by_key, expected_tokens);
            assert_eq!(raft.broker.metrics().holders, 3);
            assert_eq!(raft.broker.metrics().waiters, 0);

            assert!(matches!(
                &command,
                RaftCommand::ClientRequest {
                    grant: Some(RaftGrantPlan {
                        lock_uuid: Some(lock_uuid),
                        fencing_seed: Some(grant_seed),
                    }),
                    ..
                } if lock_uuid == &expected_lock_uuid && *grant_seed == seed
            ));
            let _ = fs::remove_dir_all(dir);
        }
    }

    #[test]
    fn threshold_maintenance_snapshots_and_retains_trailing_entries() {
        let dir = temp_dir("raft-threshold-maintenance");
        let mut cfg = test_raft_config(dir.clone());
        cfg.snapshot_max_log_entries = 2;
        cfg.snapshot_max_log_bytes = u64::MAX;
        cfg.trailing_log_entries = 1;
        let raft = BrokerRaft::open(cfg).expect("open raft");
        for _ in 0..5 {
            raft.log.append(1, RaftCommand::Noop).expect("append");
        }
        let initial_log_bytes = raft.log.log_len_bytes().expect("initial log bytes");
        {
            let mut runtime = raft.runtime.lock();
            runtime.commit_index = 5;
            runtime.last_applied = 5;
            runtime.current_term = 1;
        }

        raft.snapshot_and_compact_if_needed(false)
            .expect("maintenance compacts");

        assert_eq!(
            raft.log
                .latest_snapshot()
                .expect("snapshot")
                .last_included_index,
            5
        );
        let remaining = raft.log.read_entries().expect("remaining entries");
        assert_eq!(
            remaining
                .iter()
                .map(|entry| entry.index)
                .collect::<Vec<_>>(),
            vec![5]
        );
        let retained_log_bytes = raft.log.log_len_bytes().expect("retained log bytes");
        let compacted_bytes = initial_log_bytes.saturating_sub(retained_log_bytes);
        let telemetry = raft.telemetry_snapshot();
        assert_eq!(telemetry.log_compactions_total, 1);
        assert_eq!(telemetry.log_compacted_entries_total, 4);
        assert_eq!(telemetry.log_compacted_bytes_total, compacted_bytes);
        assert_eq!(telemetry.log_compaction_threshold_triggers_total, 1);
        assert_eq!(telemetry.log_compaction_cadence_triggers_total, 0);
        assert_eq!(telemetry.log_compaction_safety_skips_total, 0);
        assert_eq!(telemetry.log_compaction_no_commit_skips_total, 0);
        assert_eq!(telemetry.log_compaction_unapplied_commit_skips_total, 0);
        assert_eq!(telemetry.log_compaction_trailing_suffix_skips_total, 0);
        assert_eq!(telemetry.log_write_rollbacks_total, 0);
        assert_eq!(telemetry.log_write_rollback_errors_total, 0);
        assert_eq!(telemetry.log_rewrite_temp_cleanups_total, 0);
        assert_eq!(telemetry.atomic_json_temp_cleanups_total, 0);
        assert_eq!(telemetry.log_trailing_partial_recoveries_total, 0);
        assert_eq!(telemetry.log_trailing_partial_recovery_errors_total, 0);
        let metrics = raft.raft_metrics_text();
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_compactions_total 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_compacted_entries_total 4"));
        assert!(metrics.contains(&format!(
            "dd_rust_network_mutex_raft_log_compacted_bytes_total {compacted_bytes}"
        )));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_compaction_us_total "));
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_log_compaction_threshold_triggers_total 1"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_log_compaction_cadence_triggers_total 0")
        );
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_compaction_safety_skips_total 0"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_log_compaction_no_commit_skips_total 0")
        );
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_log_compaction_unapplied_commit_skips_total 0"));
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_log_compaction_trailing_suffix_skips_total 0"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_write_rollbacks_total 0"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_write_rollback_errors_total 0"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_rewrite_temp_cleanups_total 0"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_atomic_json_temp_cleanups_total 0"));
        assert!(
            metrics.contains("dd_rust_network_mutex_raft_log_trailing_partial_recoveries_total 0")
        );
        assert!(metrics
            .contains("dd_rust_network_mutex_raft_log_trailing_partial_recovery_errors_total 0"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_retained_entries 1"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_last_log_index 5"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_latest_snapshot_index 5"));
        assert!(metrics.contains("dd_rust_network_mutex_raft_log_compaction_eligible_index 4"));

        let _ = fs::remove_dir_all(dir);
    }

